use std::collections::BinaryHeap;

pub struct EventLogger {
    heap: BinaryHeap<u32>,
}

impl EventLogger {
    pub fn new() -> Self {
        EventLogger {
            heap: BinaryHeap::new(),
        }
    }

    pub fn log_event(&mut self, score: u32) {
        self.heap.push(score);
    }

    pub fn retrieve_highest(&mut self) -> Option<u32> {
        self.heap.pop()
    }

    pub fn leaderboard(&self) -> Vec<u32> {
        let mut scores: Vec<u32> = self.heap.clone().into_sorted_vec();
        scores.reverse();
        scores
    }
}

fn main() {
    let mut logger = EventLogger::new();
    logger.log_event(50);
    logger.log_event(75);
    logger.log_event(25);

    println!("Highest Score: {:?}", logger.retrieve_highest());
    println!("Leaderboard: {:?}", logger.leaderboard());
}
