```rust
use std::cmp::Ordering;
use std::collections::BinaryHeap;

pub fn real_time_event_logging() -> BinaryHeap<u32> {
    let mut heap = BinaryHeap::new();
    const MAX_CAPACITY: usize = 500;

    // Function to push a new score into the heap
    fn push_score(score: u32, heap: &mut BinaryHeap<u32>) {
        if heap.len() < MAX_CAPACITY {
            heap.push(score);
        } else {
            // Remove the lowest score when capacity is reached
            if heap.len() > 0 {
                let lowest = heap.pop().unwrap();
                if lowest < score {
                    heap.push(score);
                }
            }
        }
    }

    // Function to get the highest score (peek)
    fn peek_score(heap: &BinaryHeap<u32>) -> Option<u32> {
        heap.peek().cloned()
    }

    // Function to remove the highest score (pop)
    fn pop_score(heap: &mut BinaryHeap<u32>) -> Option<u32> {
        heap.pop()
    }

    // Example usage
    let mut heap = BinaryHeap::new();
    push_score(100, &mut heap);
    push_score(200, &mut heap);
    push_score(150, &mut heap);
    push_score(300, &mut heap);

    // Peek at the top score
    println!("Top score: {}", peek_score(&heap).unwrap());

    // Remove the top score
    let removed = pop_score(&mut heap);
    println!("Removed score: {}", removed.unwrap());

    heap
}
