public class RealTimeMessaging {

    private PriorityQueue<Message> messageQueue;

    public RealTimeMessaging() {
        // Initialize the queue with a comparator for urgency
        messageQueue = new PriorityQueue<>((a, b) -> Integer.compare(b.getUrgency(), a.getUrgency()));
    }

    // Method to add new messages to the queue
    public void addMessage(String content, int urgency) {
        Message message = new Message(content, urgency);
        messageQueue.offer(message);
    }

    // Method to retrieve and process the most urgent message
    public Message processMessage() {
        return messageQueue.poll();
    }

    // Message class to hold content and urgency
    static class Message {
        private String content;
        private int urgency;

        public Message(String content, int urgency) {
            this.content = content;
            this.urgency = urgency;
        }

        public String getContent() {
            return content;
        }

        public int getUrgency() {
            return urgency;
        }
    }
}
