import java.util.PriorityQueue;

public class RealTimeMessageQueue {
    private PriorityQueue<Message> messageQueue = new PriorityQueue<>();

    public void offer(Message message) {
        if (messageQueue.size() < 100) {
            messageQueue.offer(message);
        } else {
            // Handle overflow, e.g., log or throw exception
            System.out.println("Queue is full, cannot offer new message.");
        }
    }

    public Message poll() {
        return messageQueue.poll();
    }

    public Message peek() {
        return messageQueue.peek();
    }

    // Helper class to represent a message with urgency
    private static class Message implements Comparable<Message> {
        private String content;
        private int priority;

        public Message(String content, int priority) {
            this.content = content;
            this.priority = priority;
        }

        @Override
        public int compareTo(Message other) {
            return Integer.compare(this.priority, other.priority);
        }

        public String getContent() {
            return content;
        }

        public int getPriority() {
            return priority;
        }
    }
}
