use std::collections::HashSet;

pub fn tag_manager() -> HashSet<String> {
    let mut tags: HashSet<String> = HashSet::new();
    const MAX_TAGS: usize = 10;

    // Initialize with 10 tags
    for i in 0..MAX_TAGS {
        let tag = format!("tag_{}", i);
        tags.insert(tag);
    }

    tags
}

// Function to add a new tag
pub fn insert_tag(mut tags: HashSet<String>, tag: &str) -> Result<HashSet<String>, String> {
    if tags.contains(tag) {
        return Err(format!("Tag '{}' already exists.", tag));
    }

    if tags.len() >= MAX_TAGS {
        return Err("Maximum number of tags reached.".to_string());
    }

    tags.insert(tag.to_string());
    Ok(tags)
}

// Function to check if a tag exists
pub fn contains_tag(tags: &HashSet<String>, tag: &str) -> bool {
    tags.contains(tag)
}

// Function to remove a tag
pub fn remove_tag(mut tags: HashSet<String>, tag: &str) -> Result<HashSet<String>, String> {
    if !tags.contains(tag) {
        return Err(format!("Tag '{}' does not exist.", tag));
    }

    tags.remove(tag);
    Ok(tags)
}
