import (
	"fmt"
	"sync"
)

type Student struct {
	Name string
}

type AttendanceManager struct {
	students []Student
	capacity int
	mu       sync.Mutex
}

func NewAttendanceManager(capacity int) *AttendanceManager {
	return &AttendanceManager{
		students: make([]Student, 0, capacity),
		capacity: capacity,
	}
}

func (m *AttendanceManager) AddStudent(name string) {
	m.mu.Lock()
	defer m.mu.Unlock()

	if len(m.students) < m.capacity {
		m.students = append(m.students, Student{Name: name})
	} else {
		fmt.Println("Cannot add more students. Capacity is full.")
	}
}

func (m *AttendanceManager) CopyStudents() []Student {
	m.mu.Lock()
	defer m.mu.Unlock()

	copyStudents := make([]Student, len(m.students))
	copy(copyStudents, m.students)
	return copyStudents
}

func (m *AttendanceManager) RemoveStudent(name string) {
	m.mu.Lock()
	defer m.mu.Unlock()

	for i, student := range m.students {
		if student.Name == name {
			copy(m.students, m.students[:i]) // Replace the removed student
			break
		}
	}
}

func (m *AttendanceManager) GetTotalPresent() int {
	m.mu.Lock()
	defer m.mu.Unlock()
	return len(m.students)
}

func main() {
	manager := NewAttendanceManager(50)

	manager.AddStudent("Alice")
	manager.AddStudent("Bob")
	manager.AddStudent("Charlie")
	manager.AddStudent("David")
	manager.AddStudent("Eve")

	fmt.Printf("Total present: %d\n", manager.GetTotalPresent())

	manager.RemoveStudent("Bob")
	fmt.Printf("Total present after removal: %d\n", manager.GetTotalPresent())
}

