import (
	"fmt"
	"sync"
)

type Student struct {
	Name string
}

type AttendanceStack struct {
	students []Student
	mutex    sync.Mutex
}

func (s *AttendanceStack) Push(name string) {
	s.mutex.Lock()
	defer s.mutex.Unlock()
	if len(s.students) < 50 {
		s.students = append(s.students, Student{Name: name})
	} else {
		// If full, remove the last student
		s.students = s.students[:len(s.students)-1]
	}
}

func (s *AttendanceStack) Pop() {
	s.mutex.Lock()
	defer s.mutex.Unlock()
	if len(s.students) > 0 {
		s.students = s.students[:len(s.students)-1]
	}
}

func (s *AttendanceStack) GetCount() int {
	s.mutex.Lock()
	defer s.mutex.Unlock()
	return len(s.students)
}

func (s *AttendanceStack) CopyStack() []Student {
	s.mutex.Lock()
	defer s.mutex.Unlock()
	copy := make([]Student, len(s.students))
	copy = s.students
	return copy
}

func main() {
	attendance := &AttendanceStack{}
	attendance.Push("Alice")
	attendance.Push("Bob")
	attendance.Push("Charlie")
	attendance.Push("David")
	attendance.Push("Eve")

	fmt.Println("Current count:", attendance.GetCount())
	fmt.Println("Copied stack:", attendance.CopyStack())
}

