use std::collections::HashMap;

fn manage_document_history(doc_id: &str, content: &str) -> Result<Vec<String>, String> {
    let mut history = Vec::new();
    let mut timestamp_map = HashMap::new();

    // Check if document already exists
    if timestamp_map.contains_key(doc_id) {
        return Err(format!("Document with ID {} already exists.", doc_id));
    }

    // Add new version with timestamp
    let current_time = chrono::Utc::now().timestamp_millis();
    timestamp_map.insert(doc_id.to_string(), current_time);

    // Add to history
    history.push(format!("{} - {}", content, current_time));

    // Check if history exceeds 100 versions
    if history.len() > 100 {
        return Err("Maximum number of document versions exceeded.".to_string());
    }

    Ok(history)
}
