    let doc_version = format!("{}-{}", doc_id, timestamp);
    history.push(doc_version);

    // Check for duplicate timestamps
    if history.iter().any(|&v| v == doc_version) {
        return Err("Duplicate timestamp detected".to_string());
    }

    // Check if maximum capacity is exceeded
    if history.len() >= 100 {
        return Err("Maximum document versions reached".to_string());
    }

    Ok(history)
}
