// ReservationMap is a map of customer names to their reservations
type ReservationMap map[string][]Reservation

// NewReservationMap creates a new reservation map with a cap of 50 entries
func NewReservationMap() *ReservationMap {
	return &ReservationMap{}
}

// AddReservation adds a reservation to the map
func (rm *ReservationMap) AddReservation(name string, date string, table int) error {
	if len(*rm) >= 50 {
		return errors.New("maximum number of reservations reached")
	}

	// Check if the customer already has a reservation for the same date and table
	for _, res := range (*rm)[name] {
		if res.Date == date && res.Table == table {
			return errors.New("duplicate reservation on the same date and table")
		}
	}

	// Add the new reservation
	(*rm)[name] = append((*rm)[name], Reservation{
		Name:   name,
		Date:   date,
		Table:  table,
	})

	return nil
}

// DeleteReservation deletes a reservation from the map
func (rm *ReservationMap) DeleteReservation(name string, date string, table int) error {
	// Check if the customer has any reservations
	if _, exists := (*rm)[name]; !exists {
		return errors.New("customer not found")
	}

	// Find the reservation to delete
	var deleted bool
	for i, res := range (*rm)[name] {
		if res.Date == date && res.Table == table {
			// Remove the reservation
			(*rm)[name] = append((*rm)[name][:i], (*rm)[name][i+1:]...)
			deleted = true
			break
		}
	}

	if !deleted {
		return errors.New("reservation not found")
	}

	return nil
}

// GetReservations returns all reservations for a customer
func (rm *ReservationMap) GetReservations(name string) []Reservation {
	if _, exists := (*rm)[name]; !exists {
		return []Reservation{}
	}

	return (*rm)[name]
}

