)

type Reservation struct {
	Name    string
	Date    string
	Table   int
	Waitlist bool
}

type ReservationMap map[string][]Reservation

func NewReservationMap() ReservationMap {
	return make(map[string][]Reservation)
}

func (m *ReservationMap) AddReservation(name string, date string, table int) error {
	if len(*m) >= 50 {
		return errors.New("maximum number of reservations reached")
	}

	// Check if the table is already reserved on the same date
	for _, r := range (*m)[name] {
		if r.Date == date && r.Table == table {
			return errors.New("table already reserved on this date")
		}
	}

	// Add to the reservation map
	(*m)[name] = append((*m)[name], Reservation{
		Name:    name,
		Date:    date,
		Table:   table,
		Waitlist: false,
	})

	return nil
}

func (m *ReservationMap) AddToWaitlist(name string, date string, table int) error {
	if len(*m) >= 50 {
		return errors.New("maximum number of reservations reached")
	}

	// Check if the table is already reserved on the same date
	for _, r := range (*m)[name] {
		if r.Date == date && r.Table == table {
			return errors.New("table already reserved on this date")
		}
	}

	// Add to the waitlist
	(*m)[name] = append((*m)[name], Reservation{
		Name:    name,
		Date:    date,
		Table:   table,
		Waitlist: true,
	})

	return nil
}

func (m *ReservationMap) RemoveReservation(name string, date string, table int) error {
	if _, exists := (*m)[name]; !exists {
		return errors.New("reservation not found")
	}

	// Find the reservation to remove
	var res Reservation
	for i, r := range (*m)[name] {
		if r.Date == date && r.Table == table {
			res = (*m)[name][i]
			break
		}
	}

	if res == (Reservation{}) {
		return errors.New("reservation not found")
	}

	// Remove from the map
	delete(*m, name)

	// Promote waitlisted reservations
	m.promoteWaitlisted()

	return nil
}

func (m *ReservationMap) promoteWaitlisted() {
	// Get all waitlisted reservations
	waitlist := make([]Reservation, 0)
	for _, r := range (*m) {
		if r.Waitlist {
			waitlist = append(waitlist, r)
		}
	}

	// Sort by date and table
	sort.Slice(waitlist, func(i, j int) bool {
		return waitlist[i].Date < waitlist[j].Date || (waitlist[i].Date == waitlist[j].Date && waitlist[i].Table < waitlist[j].Table)
	})

	// Add to the reservation map
	for _, r := range waitlist {
		(*m)[r.Name] = append((*m)[r.Name], r)
	}
}

func (m *ReservationMap) GetReservations() []Reservation {
	var reservations []Reservation
	for _, r := range *m {
		reservations = append(reservations, r...)
	}
	return reservations
}

