	for i, res := range (*rm)[name] {
		if res.Date == date && res.Table == table {
			deletedRes = res
			(*rm)[name] = append((*rm)[name][:i], (*rm)[name][i+1:]...)
			break
		}
	}

	if deletedRes == (Reservation{}) {
		return errors.New("reservation not found")
	}

	return nil
}

