func (rm *ReservationMap) GetReservations(name string) []Reservation {
	if _, exists := (*rm)[name]; !exists {
		return []Reservation{}
	}

	return *rm[name]
}

// WaitlistAdd adds a reservation to the waitlist
func (rm *ReservationMap) WaitlistAdd(name string, date string, table int) error {
	if len(*rm) >= 50 {
		return errors.New("reservation map is full")
	}

	// Check if the date and table are already booked
	for _, res := range *rm[name] {
		if res.Date == date && res.Table == table {
			return errors.New("duplicate reservation on same date and table")
		}
	}

	// Add to the waitlist
	*rm[name] = append(*rm[name], Reservation{
		Name:    name,
		Date:    date,
		Table:   table,
		Waitlist: true,
	})

	return nil
}

// WaitlistRemove removes a reservation from the waitlist
func (rm *ReservationMap) WaitlistRemove(name string, date string, table int) error {
	if _, exists := (*rm)[name]; !exists {
		return errors.New("reservation not found")
	}

	// Find the reservation to remove
	var removedRes Reservation
	for i, res := range (*rm)[name] {
		if res.Date == date && res.Table == table {
			removedRes = res
			(*rm)[name] = append((*rm)[name][:i], (*rm)[name][i+1:]...)
			break
		}
	}

	if removedRes == (Reservation{}) {
		return errors.New("reservation not found")
	}

	return nil
}

// WaitlistShift shifts waitlisted reservations to active status
func (rm *ReservationMap) WaitlistShift() {
	for i := 0; i < len(*rm); i++ {
		res := (*rm)[i]
		if res.Waitlist {
			// Shift to active
			(*rm)[i] = Reservation{
				Name:    res.Name,
				Date:    res.Date,
				Table:   res.Table,
				Waitlist: false,
			}
		}
	}
