type LogStack struct {
	entries []LogEntry
	mu      sync.Mutex
}

func NewLogStack() *LogStack {
	return &LogStack{
		entries: make([]LogEntry, 0),
	}
}

func (s *LogStack) Push(timestamp int64, message string) error {
	s.mu.Lock()
	defer s.mu.Unlock()

	if len(s.entries) >= 100 {
		return errors.New("log stack is full")
	}

	s.entries = append(s.entries, LogEntry{
		Timestamp: timestamp,
		Message:   message,
	})
	return nil
}

func (s *LogStack) Pop(timestamp int64) error {
	s.mu.Lock()
	defer s.mu.Unlock()

	for i := len(s.entries) - 1; i >= 0; i-- {
		if s.entries[i].Timestamp == timestamp {
			s.entries = s.entries[:i]
			return nil
		}
	}

	return errors.New("timestamp not found")
}

