	Message   string
}

type LogStack struct {
	entries []LogEntry
	maxSize int
}

func NewLogStack(maxSize int) *LogStack {
	return &LogStack{
		entries: make([]LogEntry, 0, maxSize),
		maxSize: maxSize,
	}
}

func (s *LogStack) Push(logEntry LogEntry) error {
	if len(s.entries) >= s.maxSize {
		return errors.New("stack is full")
	}
	s.entries = append(s.entries, logEntry)
	return nil
}

func (s *LogStack) Pop(timestamp time.Time) (LogEntry, error) {
	for i := len(s.entries) - 1; i >= 0; i-- {
		if s.entries[i].Timestamp.Equal(timestamp) {
			return s.entries[i], nil
		}
	}
	return LogEntry{}, errors.New("timestamp not found")
}

