#include <iostream>
#include <stack>
#include <sstream>
#include <string>

int evaluatePostfix(const std::string &expr, std::string &errorMessage) {
    std::stack<int> stack;
    std::istringstream tokens(expr);
    std::string token;

    while (tokens >> token) {
        if (isdigit(token[0])) { // Check if the token is an integer
            stack.push(std::stoi(token));
        } else if (token == "+" || token == "-" || token == "*" || token == "/") {
            if (stack.size() < 2) {
                errorMessage = "Invalid expression";
                return 0;
            }
            int b = stack.top(); stack.pop();
            int a = stack.top(); stack.pop();

            if (token == "+") stack.push(a + b);
            else if (token == "-") stack.push(a - b);
            else if (token == "*") stack.push(a * b);
            else if (token == "/") {
                if (b == 0) {
                    errorMessage = "Division by zero";
                    return 0;
                }
                stack.push(a / b);
            }
        } else {
            errorMessage = "Invalid symbol";
            return 0;
        }
    }

    if (stack.size() != 1) {
        errorMessage = "Invalid expression";
        return 0;
    }
    return stack.top();
}

int main() {
    std::string expression = "3 4 + 2 * 7 /";
    std::string errorMessage;
    int result = evaluatePostfix(expression, errorMessage);

    if (!errorMessage.empty()) {
        std::cout << "Error: " << errorMessage << std::endl;
    } else {
        std::cout << "Result: " << result << std::endl;
    }

    return 0;
}
