using namespace std;

class PostfixEvaluator {
public:
    PostfixEvaluator() : stack() {}
    ~PostfixEvaluator() {}

    int evaluate(const string& expression) {
        stack<int> s;
        for (char c : expression) {
            if (c >= '0' && c <= '9') {
                s.push(c - '0');
            } else if (c == '+' || c == '-' || c == '*' || c == '/') {
                if (s.size() < 2) {
                    throw invalid_argument("Insufficient operands for operation");
                }
                int b = s.top();
                s.pop();
                int a = s.top();
                s.pop();
                switch (c) {
                    case '+': s.push(a + b); break;
                    case '-': s.push(a - b); break;
                    case '*': s.push(a * b); break;
                    case '/': s.push(a / b); break;
                }
            } else {
                throw invalid_argument("Invalid symbol");
            }
        }
        if (s.size() != 1) {
            throw invalid_argument("Expression is invalid");
        }
        return s.top();
    }

private:
    stack<int> stack;
};

int main() {
    PostfixEvaluator evaluator;
    try {
        string expr = "3 4 + 5 *";
        cout << "Result: " << evaluator.evaluate(expr) << endl;
    } catch (const invalid_argument& e) {
        cout << "Error: " << e.what() << endl;
    }
    return 0;
}

