fn manage_inventory(product: &str, quantity: i32) -> Result<(), String> {
    // Create a HashMap to track inventory
    let mut inventory = std::collections::HashMap::new();

    // Check if product exists in the inventory
    if let Some(mut stock) = inventory.get_mut(product) {
        // If quantity is greater than current stock, update it
        if quantity > *stock {
            *stock = quantity;
        } else if quantity < *stock {
            // If quantity is less than current stock, remove the item
            inventory.remove(product);
        }
    } else {
        // If product does not exist, add it with the given quantity
        inventory.insert(product.to_string(), quantity);
    }

    // Ensure the HashMap does not exceed 50 items
    if inventory.len() > 50 {
        return Err("Inventory exceeds maximum of 50 items".to_string());
    }

    Ok(())
}

