use std::collections::HashMap;

fn manage_inventory(product_id: &str, quantity: i32) -> Result<HashMap<String, i32>, String> {
    let mut inventory: HashMap<String, i32> = HashMap::new();

    // Insert new item
    if inventory.get(&product_id.to_string()).is_none() {
        inventory.insert(product_id.to_string(), quantity);
    } else {
        // Update existing item
        let current_quantity = inventory.get_mut(&product_id.to_string()).unwrap();
        *current_quantity += quantity;
    }

    // Check if the inventory exceeds 50 items
    if inventory.len() > 50 {
        // Remove least recently used item
        let (key, _) = inventory.iter().min_by_key(|&k| k).unwrap();
        inventory.remove(key);
    }

    Ok(inventory)
}
