    let mut inventory: HashMap<String, i32> = HashMap::new();

    // Insert or update item
    match inventory.get_mut(&product_id.to_string()) {
        Some(count) => {
            *count += quantity;
            if *count == 0 {
                inventory.remove(&product_id.to_string());
            }
        },
        None => {
            inventory.insert(product_id.to_string(), quantity);
        }
    }

    Ok(())
}

