public class ExamScheduler {

    private PriorityQueue<Examination> examQueue = new PriorityQueue<>(
        (e1, e2) -> e1.getDate().compareTo(e2.getDate())
    );

    // Add a new exam to the schedule
    public void scheduleExam(String examName, String date) {
        Examination newExam = new Examination(examName, date);
        examQueue.offer(newExam);
    }

    // Retrieve and process the earliest exam
    public void processNextExam() {
        if (examQueue.isEmpty()) {
            System.out.println("No exams scheduled.");
            return;
        }
        Examination nextExam = examQueue.poll();
        System.out.println("Processing exam: " + nextExam.getExamName() + ", Date: " + nextExam.getDate());
    }
}
