use std::collections::VecDeque;

fn elevator_scheduler() -> VecDeque<String> {
    let mut requests = VecDeque::new();
    const MAX_REQUESTS: usize = 10;

    // Function to check if a request is urgent
    fn is_urgent(floor: &str) -> bool {
        floor.contains("URGENT")
    }

    // Add a request to the queue
    fn add_request(floor: &str) -> Result<(), String> {
        if requests.len() >= MAX_REQUESTS {
            return Err("Cannot add more requests".to_string());
        }
        requests.push_back(floor.to_string());
        Ok(())
    }

    // Process requests
    fn process_requests() -> Vec<String> {
        let mut result = Vec::new();
        let mut i = 0;

        while i < requests.len() {
            let floor = requests[i].clone();
            if is_urgent(&floor) {
                result.push(floor);
                i += 1;
            } else {
                result.push(floor);
                i += 1;
            }
        }

        result
    }

    // Main function to handle requests
    fn handle_requests() -> Vec<String> {
        let mut requests = VecDeque::new();
        let mut i = 0;

        while i < MAX_REQUESTS {
            let floor = format!("FLOOR {}", i + 1);
            if add_request(&floor).is_ok() {
                i += 1;
            }
        }

        process_requests()
    }

    handle_requests()
}
