import java.util.LinkedList;
import java.util.concurrent.locks.ReentrantLock;

public class Playlist {
    private final LinkedList<Track> playlist = new LinkedList<>();
    private final ReentrantLock lock = new ReentrantLock();

    public void addFirst(Track track) {
        lock.lock();
        try {
            if (playlist.size() >= 50) {
                playlist.removeFirst();
            }
            playlist.addFirst(track);
        } finally {
            lock.unlock();
        }
    }

    public Track removeFirst() {
        lock.lock();
        try {
            if (!playlist.isEmpty()) {
                Track track = playlist.removeFirst();
                return track;
            }
            return null;
        } finally {
            lock.unlock();
        }
    }

    public Track peek() {
        lock.lock();
        try {
            if (!playlist.isEmpty()) {
                return playlist.peekFirst();
            }
            return null;
        } finally {
            lock.unlock();
        }
    }

    public int size() {
        lock.lock();
        try {
            return playlist.size();
        } finally {
            lock.unlock();
        }
    }

    // Helper class for tracks
    private static class Track {
        private String title;
        private String artist;

        public Track(String title, String artist) {
            this.title = title;
            this.artist = artist;
        }

        @Override
        public String toString() {
            return "Track{" + "title='" + title + '\'' + ", artist='" + artist + '\'' + '}';
        }
    }
}
