use std::collections::VecDeque;
use std::sync::{Mutex, MutexGuard};

fn manage_queries() -> Mutex<VecDeque<String>> {
    let deque = Mutex::new(VecDeque::new());
    // Initialize with a maximum of 10 queries
    for i in 0..10 {
        deque.lock().unwrap().push_back(format!("Query {}", i));
    }
    deque
}

// Function to push a new query
fn push_back(mut deque: MutexGuard<VecDeque<String>>, query: String) {
    if deque.len() < 10 {
        deque.push_back(query);
    } else {
        // Automatically drop the oldest query
        deque.pop_front();
        deque.push_back(query);
    }
}

// Function to pop the oldest query
fn pop_front(mut deque: MutexGuard<VecDeque<String>>) {
    if !deque.is_empty() {
        deque.pop_front();
    }
}

// Function to peek at the next query without removing it
fn front(mut deque: MutexGuard<VecDeque<String>>) -> Option<String> {
    if !deque.is_empty() {
        Some(deque.front().cloned().unwrap())
    } else {
        None
    }
}

// Thread-safe access to the VecDeque
fn get_deque() -> Mutex<VecDeque<String>> {
    manage_queries()
}
