        # Add student to the queue
        heapq.heappush(classroom_queue, (student.grade_level, student.name))
        # Ensure the queue does not exceed 30 students
        if len(classroom_queue) > 30:
            heapq.heappop(classroom_queue)

    def remove_student(student):
        # Remove student from the queue
        for i in range(len(classroom_queue)):
            if classroom_queue[i][0] == student.grade_level and classroom_queue[i][1] == student.name:
                heapq.heappop(classroom_queue)
                break

    return add_student, remove_student

