#include <mutex>
#include <stdexcept>

class ConferenceScheduler {
private:
    std::priority_queue<int, std::vector<int>, std::greater<int>> queue;
    std::mutex mtx;
    static const int MAX_SPEAKERS = 20;

public:
    void push(int rating) {
        std::lock_guard<std::mutex> lock(mtx);
        if (queue.size() >= MAX_SPEAKERS) {
            throw std::runtime_error("Cannot add speaker: queue is full.");
        }
        queue.push(rating);
    }

    int pop() {
        std::lock_guard<std::mutex> lock(mtx);
        if (queue.empty()) {
            throw std::runtime_error("Queue is empty.");
        }
        int rating = queue.top();
        queue.pop();
        return rating;
    }

    int top() {
        std::lock_guard<std::mutex> lock(mtx);
        if (queue.empty()) {
            throw std::runtime_error("Queue is empty.");
        }
        return queue.top();
    }

    bool isFull() {
        std::lock_guard<std::mutex> lock(mtx);
        return queue.size() == MAX_SPEAKERS;
    }
};

