import java.util.HashMap;
import java.util.Map;
import java.util.Set;
import java.util.HashSet;
import java.util.concurrent.locks.ReentrantLock;

public class InventorySystem {
    private final Map<String, Integer> inventoryMap = new HashMap<>();
    private final ReentrantLock lock = new ReentrantLock();
    private final int maxCapacity = 100;
    private final Set<String> removedItems = new HashSet<>();

    public void addProduct(String productName, int quantity) {
        lock.lock();
        try {
            if (inventoryMap.containsKey(productName)) {
                inventoryMap.put(productName, inventoryMap.get(productName) + quantity);
            } else {
                inventoryMap.put(productName, quantity);
            }
            if (inventoryMap.size() > maxCapacity) {
                removeLeastRecentlyUsedItem();
            }
        } finally {
            lock.unlock();
        }
    }

    public void updateProductQuantity(String productName, int quantity) {
        lock.lock();
        try {
            if (inventoryMap.containsKey(productName)) {
                inventoryMap.put(productName, inventoryMap.get(productName) + quantity);
                if (inventoryMap.size() > maxCapacity) {
                    removeLeastRecentlyUsedItem();
                }
            }
        } finally {
            lock.unlock();
        }
    }

    public int getStockLevel(String productName) {
        lock.lock();
        try {
            return inventoryMap.getOrDefault(productName, 0);
        } finally {
            lock.unlock();
        }
    }

    public void removeProduct(String productName) {
        lock.lock();
        try {
            if (inventoryMap.containsKey(productName)) {
                inventoryMap.remove(productName);
                removedItems.add(productName);
                if (inventoryMap.size() < maxCapacity) {
                    // No need to remove least recently used item as capacity is not exceeded
                } else {
                    removeLeastRecentlyUsedItem();
                }
            }
        } finally {
            lock.unlock();
        }
    }

    private void removeLeastRecentlyUsedItem() {
        lock.lock();
        try {
            if (!inventoryMap.isEmpty()) {
                Set<Map.Entry<String, Integer>> entries = inventoryMap.entrySet();
                int leastUsedIndex = 0;
                for (int i = 1; i < entries.size(); i++) {
                    if (entries.get(i).getValue() < entries.get(leastUsedIndex).getValue()) {
                        leastUsedIndex = i;
                    }
                }
                inventoryMap.remove(entries.get(leastUsedIndex).getKey());
            }
        } finally {
            lock.unlock();
        }
    }
}
