def manage_tabs(max_tabs=10):
    stack = []
    remaining_tabs = max_tabs

    def push_tab(tab):
        nonlocal remaining_tabs
        if remaining_tabs > 0:
            stack.append(tab)
            remaining_tabs -= 1
            print(f"Tab '{tab}' opened. Remaining tabs: {remaining_tabs}")
        else:
            print("Cannot open more tabs.")

    def pop_tab():
        nonlocal remaining_tabs
        if stack:
            tab = stack.pop()
            remaining_tabs += 1
            print(f"Tab '{tab}' closed. Remaining tabs: {remaining_tabs}")
        else:
            print("No tabs to close.")

    return {
        'push': push_tab,
        'pop': pop_tab
    }

