func (ts *TaskStack) Push(task Task) {
	if len(ts.tasks) < ts.capacity {
		ts.tasks = append(ts.tasks, task)
	} else {
		ts.pop()
		ts.Push(task)
	}
}

func (ts *TaskStack) Pop() Task {
	if len(ts.tasks) > 0 {
		task := ts.tasks[len(ts.tasks)-1]
		ts.tasks = ts.tasks[:len(ts.tasks)-1]
		return task
	}
	return Task{}
}

func (ts *TaskStack) Peek() Task {
	if len(ts.tasks) > 0 {
		return ts.tasks[len(ts.tasks)-1]
	}
	return Task{}
}

func (ts *TaskStack) pop() {
	if len(ts.tasks) > 0 {
		ts.tasks = ts.tasks[:len(ts.tasks)-1]
	}
}

