package main

import "fmt"

func processScores(scores []int) (int, int, float64) {
	if len(scores) == 0 {
		return 0, 0, 0
	}

	maxScore := scores[0]
	minScore := scores[0]
	sum := scores[0]

	for i := 1; i < len(scores); i++ {
		if scores[i] > maxScore {
			maxScore = scores[i]
		}
		if scores[i] < minScore {
			minScore = scores[i]
		}
		sum += scores[i]
	}

	average := float64(sum) / float64(len(scores))
