import java.util.Stack;

public class MaxNonConsecutiveSum {
    public static int maxNonConsecutiveSum(int[] nums) {
        HashMap<Integer, Integer> map = new HashMap<>();
        Stack<Integer> stack = new Stack<>();

        for (int i = 0; i < nums.length; i++) {
            if (stack.isEmpty() || nums[i] > nums[stack.peek()] && i - stack.peek() > 1) {
                map.put(i, nums[i]);
                stack.push(i);
            } else {
                // If current element is less than the last element in the stack, skip it
                // and add the previous sum to the current element
                int prevSum = map.get(stack.pop());
                map.put(i, prevSum + nums[i]);
                stack.push(i);
            }
        }

        return map.get(stack.peek());
    }

    public static void main(String[] args) {
        int[] nums = {3, 2, 5, 1, 4};
        System.out.println(maxNonConsecutiveSum(nums)); // Output: 10 (3 + 5 + 1)
    }
}
