public class MaxNonConsecutiveSum {
    public static int maxNonConsecutiveSum(int[] nums) {
        HashMap<Integer, Integer> map = new HashMap<>();
        Stack<Integer> stack = new Stack<>();

        for (int i = 0; i < nums.length; i++) {
            if (stack.size() > 0 && stack.peek() + 1 == i) {
                // Skip if current index is consecutive to the top of the stack
                continue;
            }
            // Add current index to map and stack
            map.put(i, nums[i]);
            stack.push(i);
        }

        int maxSum = 0;
        for (int i : map.keySet()) {
            maxSum += map.get(i);
        }
        return maxSum;
    }

    public static void main(String[] args) {
        int[] nums = {3, 2, 5, 1, 4};
        System.out.println(maxNonConsecutiveSum(nums)); // Output: 10 (3 + 5 + 1)
    }
}
