public class SocialNetwork {

    private HashMap<String, HashSet<String>> relationships = new HashMap<>();
    private List<String[]> followEvents = new ArrayList<>();

    // Method to follow a user
    public void follow(String follower, String followee) {
        if (!relationships.containsKey(follower)) {
            relationships.put(follower, new HashSet<>());
        }
        relationships.get(follower).add(followee);
        followEvents.add(new String[]{follower, followee});
    }

    // Method to find the latest common follower between two users
    public String findLatestCommonFollower(String user1, String user2) {
        HashSet<String> followersUser1 = getFollowers(user1);
        HashSet<String> followersUser2 = getFollowers(user2);

        String latestCommonFollower = null;
        for (int i = followEvents.size() - 1; i >= 0; i--) {
            String[] event = followEvents.get(i);
            String follower = event[0];
            String followee = event[1];
            if (followee.equals(user1) && followersUser2.contains(follower) 
             || followee.equals(user2) && followersUser1.contains(follower)) {
                latestCommonFollower = follower;
                break;
            }
        }
        return latestCommonFollower;
    }

    // Method to suggest new friends through mutual connections
    public Set<String> suggestFriends(String user) {
        HashSet<String> directFollowees = relationships.getOrDefault(user, new HashSet<>());
        HashSet<String> mutualConnections = new HashSet<>();

        for (String followee : directFollowees) {
            HashSet<String> secondDegreeConnections = relationships.getOrDefault(followee, new HashSet<>());
            for (String connection : secondDegreeConnections) {
                if (!connection.equals(user) && !directFollowees.contains(connection)) {
                    mutualConnections.add(connection);
                }
            }
        }
        return mutualConnections;
    }

    // Helper method to get followers of a user
    private HashSet<String> getFollowers(String user) {
        HashSet<String> followers = new HashSet<>();
        for (Map.Entry<String, HashSet<String>> entry : relationships.entrySet()) {
            if (entry.getValue().contains(user)) {
                followers.add(entry.getKey());
            }
        }
        return followers;
    }

    public static void main(String[] args) {
        SocialNetwork network = new SocialNetwork();
        network.follow("Alice", "Bob");
        network.follow("Carol", "Bob");
        network.follow("David", "Alice");
        network.follow("Eve", "Alice");
        System.out.println("Latest common follower of Bob and Alice: " + network.findLatestCommonFollower("Bob", "Alice"));
        System.out.println("Friend suggestions for David: " + network.suggestFriends("David"));
    }
}
