public class MaxSubarraySumWithStack {

    public static int getMaxSum(int[] nums) {
        if (nums == null || nums.length == 0) {
            return 0;
        }

        Stack<Integer> stack = new Stack<>();
        int maxSum = Integer.MIN_VALUE, currentSum = 0;

        for (int num : nums) {
            currentSum += num;
            stack.push(num);

            if (currentSum > maxSum) {
                maxSum = currentSum;
            }

            if (currentSum < 0) {
                while (!stack.isEmpty()) {
                    currentSum -= stack.pop();
                }
            }
        }

        return maxSum;
    }

    public static void main(String[] args) {
        int[] nums = {-2, 1, -3, 4, -1, 2, 1, -5, 4};
        System.out.println(getMaxSum(nums)); // 6 (subarray: [4, -1, 2, 1])
    }
}
