public class MaxSubarraySum {
    public static int maxSubarraySum(int[] arr) {
        Stack<Integer> stack = new Stack<>();
        int maxSum = Integer.MIN_VALUE;
        int currentSum = 0;

        for (int num : arr) {
            if (stack.size() < 10) {
                stack.push(num);
                currentSum += num;
                if (currentSum > maxSum) {
                    maxSum = currentSum;
                }
            } else {
                // Remove elements from the stack if it exceeds 10 elements
                while (stack.size() > 10) {
                    stack.pop();
                    currentSum -= stack.pop();
                }
                stack.push(num);
                currentSum += num;
                if (currentSum > maxSum) {
                    maxSum = currentSum;
                }
            }
        }

        return maxSum;
    }
