public class MaxSubarraySum {
    public static int maxSubarraySum(int[] arr) {
        Stack<Integer> stack = new Stack<>();
        int maxSum = Integer.MIN_VALUE;
        int currentSum = 0;

        for (int num : arr) {
            if (stack.size() < 10) {
                stack.push(num);
                currentSum += num;
                if (currentSum > maxSum) {
                    maxSum = currentSum;
                }
            } else {
                // If stack is full, pop the smallest element
                int smallest = stack.peek();
                if (num < smallest) {
                    stack.pop();
                    currentSum -= smallest;
                    stack.push(num);
                    currentSum += num;
                    if (currentSum > maxSum) {
                        maxSum = currentSum;
                    }
                } else {
                    // If num is not smaller than the smallest, push it
                    stack.push(num);
                    currentSum += num;
                    if (currentSum > maxSum) {
                        maxSum = currentSum;
                    }
                }
            }
        }

        return maxSum;
    }
}

public class MaxSubarraySum {
    public static int maxSubarraySum(int[] arr) {
        ArrayList<Integer> stack = new ArrayList<>();
        int maxSum = Integer.MIN_VALUE;
        int currentSum = 0;

        for (int num : arr) {
            // Push the current number to the stack
            stack.add(num);
            currentSum += num;

            // If stack size exceeds 10, pop the top element
            if (stack.size() > 10) {
                stack.remove(stack.size() - 1);
                currentSum -= stack.get(stack.size() - 1);
            }

            // Update the maximum sum
            if (currentSum > maxSum) {
                maxSum = currentSum;
            }
        }

        return maxSum;
    }
