fn manage_students(mut roster: BTreeMap<String, String>) -> BTreeMap<String, String> {
    let mut new_roster = roster.clone();

    // Add a new student
    let id = "12345".to_string();
    let name = "Alice".to_string();
    if new_roster.insert(id, name).is_none() {
        // If insert fails, it means the ID already exists
        // We do not modify the map, so we return a copy
        return new_roster;
    }

    // Remove a student
    let id_to_remove = "12345".to_string();
    if new_roster.remove(&id_to_remove).is_none() {
        // If remove fails, it means the ID does not exist
        // We do not modify the map, so we return a copy
        return new_roster;
    }

    // Check if the size exceeds 50
    if new_roster.len() > 50 {
        // Remove the oldest student (first entry)
        if let Some((_, value)) = new_roster.iter().next() {
            new_roster.remove(&value);
        }
    }

    new_roster
