use std::collections::HashSet;

pub fn user_auth_manager() -> HashSet<String> {
    let mut auth_set = HashSet::new();
    const MAX_USERS: usize = 100;

    // Check if user is authorized
    fn is_authorized(user_id: &str, auth_set: &HashSet<String>) -> bool {
        auth_set.contains(user_id)
    }

    // Check if user is inactive (not logged in for 30 days)
    fn is_inactive(user_id: &str, auth_set: &HashSet<String>) -> bool {
        !auth_set.contains(user_id)
    }

    // Register a new user
    fn register_user(user_id: &str, auth_set: &mut HashSet<String>) -> Result<(), String> {
        if auth_set.len() >= MAX_USERS {
            return Err("System capacity exceeded".to_string());
        }
        auth_set.insert(user_id.to_string());
        Ok(())
    }

    // Remove a user
    fn remove_user(user_id: &str, auth_set: &mut HashSet<String>) -> Result<(), String> {
        if auth_set.contains(user_id) {
            auth_set.remove(user_id);
            Ok(())
        } else {
            Err("User not found".to_string())
        }
    }

    // Clear inactive users
    fn clear_inactive_users(auth_set: &mut HashSet<String>) {
        let now = chrono::Utc::now().timestamp_millis();
        let thirty_days_ago = now - 30 * 24 * 60 * 60 * 1000;

        for user_id in auth_set.drain_filter(|user_id| {
            let timestamp: i64 = user_id.parse().unwrap();
            timestamp > thirty_days_ago
        }) {
            // Do nothing, as we are removing the user
        }
    }

    // Main function
    let mut auth_set = HashSet::new();
    auth_set.insert("user1".to_string());
    auth_set.insert("user2".to_string());

    // Example usage
    let result = register_user("user3", &mut auth_set);
    if let Err(e) = result {
        eprintln!("Error registering user: {}", e);
    }

    clear_inactive_users(&mut auth_set);

    auth_set
}
