#include <iostream>
using namespace std;

class GuestList {
private:
    int capacity;
    int size;
    int* stack;

public:
    GuestList(int maxCapacity) : capacity(maxCapacity), size(0), stack(new int[maxCapacity]) {}

    void push(int guest) {
        if (size == capacity) {
            cout << "Stack is full. Cannot add guest." << endl;
            return;
        }
        stack[size++] = guest;
    }

    int pop() {
        if (size == 0) {
            cout << "Error: No guests to remove." << endl;
            return -1;
        }
        int guest = stack[size - 1];
        stack[size - 1] = 0; // Clear the guest
        size--;
        return guest;
    }

    bool isFull() {
        return size == capacity;
    }

    bool isEmpty() {
        return size == 0;
    }
};

