from collections import OrderedDict

def manage_task_prioritization(tasks):
    task_order = OrderedDict()
    for task in tasks:
        task_order[task] = 0  # Priority is initialized to 0

    def update_priority(task, new_priority):
        if new_priority < 0:
            new_priority = 0
        task_order[task] = new_priority

    def move_task_to_end(task):
        task_order.move_to_end(task)

