    stack<Account*> accounts;
    static const int MAX_ACCOUNTS = 300;
public:
    void push(Account* account) {
        if (accounts.size() < MAX_ACCOUNTS) {
            accounts.push(account);
            cout << "Account pushed." << endl;
        } else {
            throw out_of_range("Maximum number of accounts reached.");
        }
    }
    Account* pop() {
        if (!accounts.empty()) {
            Account* account = accounts.top();
            accounts.pop();
            cout << "Account popped." << endl;
            return account;
        } else {
            throw out_of_range("No accounts to pop.");
        }
    }
    bool isEmpty() const {
        return accounts.empty();
    }
    bool isFull() const {
        return accounts.size() == MAX_ACCOUNTS;
    }
};

