class AccountManager {
private:
    std::vector<Account*> accounts;
    std::mutex mtx;
    std::string logFile;
    bool isRunning = true;
public:
    AccountManager(const std::string& logFile) : logFile(logFile) {}
    void addAccount(Account* account) {
        std::lock_guard<std::mutex> lock(mtx);
        accounts.push_back(account);
    }
    void removeAccount(Account* account) {
        std::lock_guard<std::mutex> lock(mtx);
        auto it = std::find(accounts.begin(), accounts.end(), account);
        if (it != accounts.end()) {
            accounts.erase(it);
        }
    }
    void saveStateToFile() {
        std::ofstream file(logFile, std::ios::out | std::ios::trunc);
        if (!file) throw std::runtime_error("Failed to open file for saving");
        for (auto* acc : accounts) {
            file << acc->balance << "\n";
        }
    }
    void run() {
        while (isRunning) {
            std::cout << "Enter command (add, remove, deposit, withdraw, show, exit): ";
            std::string cmd;
            std::cin >> cmd;
            if (cmd == "exit") {
                isRunning = false;
                break;
            } else if (cmd == "add") {
                double initialBalance;
                std::cout << "Enter initial balance: ";
                std::cin >> initialBalance;
                Account* account = Account::createAccount(initialBalance);
                addAccount(account);
                std::cout << "Account added.\n";
            } else if (cmd == "remove") {
                double initialBalance;
                std::cout << "Enter initial balance to remove: ";
                std::cin >> initialBalance;
                Account* account = Account::createAccount(initialBalance);
                removeAccount(account);
                std::cout << "Account removed.\n";
            } else if (cmd == "deposit") {
                double amount;
                std::cout << "Enter deposit amount: ";
                std::cin >> amount;
                if (amount < 0) throw std::invalid_argument("Deposit amount cannot be negative");
                for (auto* acc : accounts) {
                    if (acc->balance >= amount) {
                        acc->deposit(amount);
                        std::cout << "Deposited " << amount << ".\n";
                        break;
                    }
                }
            } else if (cmd == "withdraw") {
                double amount;
                std::cout << "Enter withdrawal amount: ";
                std::cin >> amount;
                if (amount < 0) throw std::invalid_argument("Withdrawal amount cannot be negative");
                for (auto* acc : accounts) {
                    if (acc->balance >= amount) {
                        acc->withdraw(amount);
                        std::cout << "Withdrew " << amount << ".\n";
                        break;
                    }
                }
            } else if (cmd == "show") {
                for (auto* acc : accounts) {
                    std::cout << "Account balance: " << acc->balance << ".\n";
                }
            } else {
                std::cout << "Invalid command.\n";
            }
        }
        saveStateToFile();
        std::cout << "Program exited.\n";
    }
};

int main() {
    std::string logFile = "account_log.txt";
    AccountManager manager(logFile);
    manager.run();
    return 0;
}

