package main

import (
	"fmt"
	"sync"
)

type Message struct {
	User   string
	Message string
}

func main() {
	// Create a fixed-size channel to store up to 200 messages
	messageChan := make(chan Message, 200)

	// Mutex for synchronization
	mutex := &sync.Mutex{}

	// Simulate user messages
	userMessages := []Message{
		{"Alice", "Hello"},
		{"Bob", "Hi there"},
		{"Charlie", "How are you?"},
		{"David", "I'm doing well"},
		{"Eve", "Thanks"},
		{"Frank", "See you later"},
		{"Grace", "Goodbye"},
		{"Hank", "Have a great day"},
		{"Ivy", "You too"},
		{"Jack", "Bye"},
	}

	// Send messages to the channel
	for _, msg := range userMessages {
		mutex.Lock()
		defer mutex.Unlock()
		messageChan <- msg
	}

	// Receive messages from the channel
	for len(messageChan) > 0 {
		msg := <-messageChan
		fmt.Printf("Received: %s - %s\n", msg.User, msg.Message)
	}
}

package main

import (
	"fmt"
	"sync"
)

type Message struct {
	Text string
}

type ChatServer struct {
	msgChan     chan Message
	userCount   int
	msgCapacity int
	mutex       sync.Mutex
}

func NewChatServer(msgCapacity int) *ChatServer {
	return &ChatServer{
		msgChan:     make(chan Message, msgCapacity),
		userCount:   0,
		msgCapacity: msgCapacity,
	}
}

func (s *ChatServer) Send(message Message) {
	s.mutex.Lock()
	defer s.mutex.Unlock()
	if len(s.msgChan) < s.msgCapacity {
		s.msgChan <- message
		s.userCount++
	} else {
		fmt.Println("Channel is full. Cannot send message.")
	}
}

func (s *ChatServer) Receive() (Message, bool) {
	s.mutex.Lock()
	defer s.mutex.Unlock()
	if len(s.msgChan) == 0 {
		return Message{}, false
	}
	message := <-s.msgChan
	s.userCount--
	return message, true
}

func main() {
	server := NewChatServer(200)
	go func() {
		for {
			msg := Message{"Hello from client"}
			server.Send(msg)
		}
	}()

	for {
		msg, ok := server.Receive()
		if !ok {
			break
		}
		fmt.Printf("Received: %s\n", msg.Text)
	}
}

package main

import (
	"fmt"
	"sync"
)

type Message struct {
	content string
}

type ChatServer struct {
	msgChan     chan Message
	userCount   int
	msgCapacity int
	mutex       sync.Mutex
}

func NewChatServer(msgCapacity int) *ChatServer {
	return &ChatServer{
		msgChan:     make(chan Message, msgCapacity),
		userCount:   0,
		msgCapacity: msgCapacity,
	}
}

func (s *ChatServer) Send(message Message) {
	s.mutex.Lock()
	defer s.mutex.Unlock()

	if len(s.msgChan) >= s.msgCapacity {
		return
	}

	s.msgChan <- message
	s.userCount++
}

func (s *ChatServer) Receive() (Message, bool) {
	s.mutex.Lock()
	defer s.mutex.Unlock()

	if len(s.msgChan) == 0 {
		return Message{}, false
	}

	msg := <-s.msgChan
	s.userCount--
	return msg, true
}

func main() {
	server := NewChatServer(200)

	go func() {
		for {
			msg := Message{"Hello from client"}
			server.Send(msg)
		}
	}()

	for i := 0; i < 200; i++ {
		msg, ok := server.Receive()
		if ok {
			fmt.Printf("Received: %s\n", msg.content)
		}
	}
