from collections import defaultdict

def evaluate_expression(expr):
    # Use a defaultdict to cache results
    cache = defaultdict(dict)

    # Define operations and their precedence
    OPERATIONS = {
        '+': 1,
        '-': 1,
        '*': 2,
        '/': 2,
        '(': 0,
        ')': 0
    }

    # Function to apply operation
    def apply_operation(a, b, op):
        if op == '+':
            return a + b
        elif op == '-':
            return a - b
        elif op == '*':
            return a * b
        elif op == '/':
            return a / b
        else:
            raise ValueError("Invalid operation")

    # Function to parse the expression
    def parse_expression(expr):
        tokens = []
        i = 0
        while i < len(expr):
            if expr[i].isdigit():
                j = i
                while j < len(expr) and expr[j].isdigit():
                    j += 1
                tokens.append(int(expr[i:j]))
                i = j
            elif expr[i] in "*/-+()":
                tokens.append(expr[i])
                i += 1
            else:
                i += 1
        return tokens

    # Function to evaluate the expression
    def evaluate(tokens):
        stack = []
        i = 0
        while i < len(tokens):
            if tokens[i] == '(':
                stack.append(i)
                i += 1
            elif tokens[i] == ')':
                i += 1
                # Pop until '(' is found
                while stack and stack[-1] != '(':
                    right = stack.pop()
                    # Apply operation
                    left = tokens[right]
                    op = tokens[i-1]
                    stack.append(apply_operation(left, tokens[i+1], op))
                    i += 2
            else:
                # Handle numbers and operations
                if i < len(tokens) and tokens[i] in OPERATIONS:
                    op = tokens[i]
                    i += 1
                    if i < len(tokens) and tokens[i] in OPERATIONS:
                        right = tokens[i]
                        i += 1
                        stack.append(apply_operation(tokens[i-1], right, op))
                    else:
                        stack.append(tokens[i-1])
                else:
                    stack.append(tokens[i])
                    i += 1
        return stack[0]

    # Check if expression is valid
    if not expr or not expr.strip():
        raise ValueError("Invalid expression")

    # Check if expression is in cache
    if expr in cache:
        return cache[expr]

    # Parse and evaluate the expression
    tokens = parse_expression(expr)
    result = evaluate(tokens)

    # Store in cache
    cache[expr] = result

    return result

