                # Apply operation
                left = int(tokens[i-1])
                right = int(tokens[i+1])
                result = left + right if tokens[i] == '+' else left - right if tokens[i] == '-' else left * right if tokens[i] == '*' else left / right
                tokens[i] = str(result)
                i += 2
            else:
                i += 1
        return int(tokens[0])

    # Evaluate the expression with precedence
    def evaluate(expr):
        # Remove whitespace
        expr = expr.replace(" ", "")
        # Process parentheses
        def helper(s):
            nonlocal i
            i = 0
            res = []
            while i < len(s):
                if s[i] == '(':
                    i += 1
                    res.append(helper(s[i:]))
                    i += 1
                elif s[i] == ')':
                    i += 1
                    break
                else:
                    res.append(s[i])
                    i += 1
            return ''.join(res)
        # Process the expression
        expr = helper(expr)
        # Apply operations
        return apply_ops(expr, OPERATIONS)

    # Main function
    def compute(expr):
        # Check if the expression is valid
        if not expr:
            return None
        # Check if the expression is a number
        if expr.isdigit():
            return int(expr)
        # Check if the expression has only one number
        if len(expr) == 1:
            return int(expr)
        # Check if the expression has only one operation
        if len(expr) == 2:
            return eval(expr)
        # Evaluate the expression
        return evaluate(expr)

    # Cache results
    cache['expr'] = compute(expr)
