from collections import defaultdict

def evaluate_expression(expr):
    # Define the allowed operations
    allowed_ops = {'+', '-', '*', '/'}

    # Use a defaultdict to cache results
    cache = defaultdict(int)

    # Stack for handling parentheses and operations
    stack = []

    # Tokenize the expression
    tokens = []
    i = 0
    while i < len(expr):
        if expr[i].isdigit():
            num = 0
            while i < len(expr) and expr[i].isdigit():
                num = num * 10 + int(expr[i])
                i += 1
            tokens.append(num)
        elif expr[i] in allowed_ops:
            tokens.append(expr[i])
            i += 1
        elif expr[i] == '(':
            stack.append(i)
            i += 1
        elif expr[i] == ')':
            i += 1
            while stack and stack[-1] != '(':
                stack.pop()
        else:
            i += 1

    # Process tokens
    i = 0
    while i < len(tokens):
        if isinstance(tokens[i], int):
            # If it's a number, push to stack
            stack.append(tokens[i])
            i += 1
        elif tokens[i] in allowed_ops:
            # Perform operation
            if not stack:
                raise ValueError("Invalid expression")
            b = stack.pop()
            a = stack.pop()
            if tokens[i] == '+':
                stack.append(a + b)
            elif tokens[i] == '-':
                stack.append(a - b)
            elif tokens[i] == '*':
                stack.append(a * b)
            elif tokens[i] == '/':
                if b == 0:
                    raise ZeroDivisionError("Division by zero")
                stack.append(a // b)
            i += 1
        elif tokens[i] == '(':
            # Push index to stack for later processing
            stack.append(i)
            i += 1
        elif tokens[i] == ')':
            # Pop until '(' is found
            while stack and stack[-1] != '(':
                stack.pop()
            stack.pop()  # Remove '('
            i += 1

    # Check if stack is empty
    if not stack:
        return 0
    return stack[0]
