import java.util.concurrent.ConcurrentHashMap;
import java.util.Iterator;
import java.util.Map;

public class SessionManager {
    private static final int MAX_ACTIVE_SESSIONS = 500;
    private static final long INACTIVITY_LIMIT = 30 * 60 * 1000; // 30 minutes in milliseconds
    private ConcurrentHashMap<String, Long> sessions = new ConcurrentHashMap<>();

    public synchronized boolean addSession(String sessionId) {
        long currentTime = System.currentTimeMillis();
        cleanupInactiveSessions();
        if (sessions.size() >= MAX_ACTIVE_SESSIONS) {
            return false; // Cannot add session, active session limit reached
        }
        sessions.put(sessionId, currentTime);
        return true;
    }

    public synchronized void cleanupInactiveSessions() {
        long currentTime = System.currentTimeMillis();
        Iterator<Map.Entry<String, Long>> iterator = sessions.entrySet().iterator();
        while (iterator.hasNext()) {
            Map.Entry<String, Long> entry = iterator.next();
            if (currentTime - entry.getValue() > INACTIVITY_LIMIT) {
                iterator.remove();
            }
        }
    }
}
