import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicInteger;

public class SessionManager {
    private final ConcurrentHashMap<String, Session> sessionMap = new ConcurrentHashMap<>();
    private final AtomicInteger operationCount = new AtomicInteger(0);

    public void createSession(String sessionId) {
        if (operationCount.get() >= 15) {
            throw new IllegalStateException("Maximum number of operations reached");
        }
        sessionMap.put(sessionId, new Session());
        operationCount.incrementAndGet();
    }

    public Session readSession(String sessionId) {
        if (operationCount.get() >= 15) {
            throw new IllegalStateException("Maximum number of operations reached");
        }
        return sessionMap.get(sessionId);
    }

    public void updateSession(String sessionId, Object data) {
        if (operationCount.get() >= 15) {
            throw new IllegalStateException("Maximum number of operations reached");
        }
        sessionMap.put(sessionId, new Session(data));
        operationCount.incrementAndGet();
    }

    public void deleteSession(String sessionId) {
        if (operationCount.get() >= 15) {
            throw new IllegalStateException("Maximum number of operations reached");
        }
        sessionMap.remove(sessionId);
        operationCount.incrementAndGet();
    }

    public void expireSession(String sessionId) {
        if (operationCount.get() >= 15) {
            throw new IllegalStateException("Maximum number of operations reached");
        }
        sessionMap.remove(sessionId);
        operationCount.incrementAndGet();
    }

    private static class Session {
        private final String id;
        private final Object data;

        Session() {
            this.id = "session_" + System.currentTimeMillis();
            this.data = null;
        }

        Session(Object data) {
            this.id = "session_" + System.currentTimeMillis();
            this.data = data;
        }

        public String getId() {
            return id;
        }

        public Object getData() {
            return data;
        }
    }
}
