import java.util.*;

public class MergeSortedLinkedLists {
    public static LinkedList<Integer> mergeSortedLists(List<LinkedList<Integer>> lists) {
        PriorityQueue<Node> minHeap = new PriorityQueue<>(Comparator.comparingInt(node -> node.value));
        LinkedList<Integer> mergedList = new LinkedList<>();

        for (LinkedList<Integer> list : lists) {
            if (list != null && !list.isEmpty()) {
                minHeap.offer(new Node(list.getFirst(), list.listIterator(1)));
            }
        }

        while (!minHeap.isEmpty() && mergedList.size() < 10000) {
            Node current = minHeap.poll();
            mergedList.add(current.value);
            if (current.iterator.hasNext()) {
                minHeap.offer(new Node(current.iterator.next(), current.iterator));
            }
        }

        return mergedList;
    }

    private static class Node {
        int value;
        ListIterator<Integer> iterator;

        Node(int value, ListIterator<Integer> iterator) {
            this.value = value;
            this.iterator = iterator;
        }
    }

    public static void main(String[] args) {
        LinkedList<Integer> list1 = new LinkedList<>(Arrays.asList(1, 4, 7));
        LinkedList<Integer> list2 = new LinkedList<>(Arrays.asList(2, 5, 8));
        LinkedList<Integer> list3 = new LinkedList<>(Arrays.asList(3, 6, 9));
        List<LinkedList<Integer>> lists = Arrays.asList(list1, list2, list3);

        LinkedList<Integer> result = mergeSortedLists(lists);
        System.out.println(result);
    }
}
