import java.util.LinkedList;
import java.util.PriorityQueue;

public class MergeSortedLinkedLists {

    public static LinkedList<Integer> mergeSortedLinkedLists(LinkedList<Integer>... lists) {
        if (lists == null || lists.length == 0) {
            return new LinkedList<>();
        }

        PriorityQueue<Integer> minHeap = new PriorityQueue<>();

        for (LinkedList<Integer> list : lists) {
            if (list != null) {
                for (Integer num : list) {
                    minHeap.offer(num);
                }
            }
        }

        LinkedList<Integer> result = new LinkedList<>();
        while (!minHeap.isEmpty()) {
            result.add(minHeap.poll());
        }

        return result;
    }

    // Test case
    public static void main(String[] args) {
        LinkedList<Integer> list1 = new LinkedList<>(List.of(1, 3, 5));
        LinkedList<Integer> list2 = new LinkedList<>(List.of(2, 4, 6));
        LinkedList<Integer> list3 = new LinkedList<>(List.of(7, 8, 9));

        LinkedList<Integer> merged = mergeSortedLinkedLists(list1, list2, list3);
        System.out.println("Merged List: " + merged);
    }
}
