import java.util.*;

public class MergeSortedLinkedLists {
    public static void main(String[] args) {
        // Example usage
        LinkedList<Integer> list1 = new LinkedList<>();
        list1.add(1);
        list1.add(3);
        list1.add(5);

        LinkedList<Integer> list2 = new LinkedList<>();
        list2.add(2);
        list2.add(4);
        list2.add(6);

        LinkedList<Integer> list3 = new LinkedList<>();
        list3.add(7);
        list3.add(8);

        mergeSortedLinkedLists(list1, list2, list3);
    }

    public static void mergeSortedLinkedLists(LinkedList<Integer>... lists) {
        if (lists == null || lists.length == 0) {
            return;
        }

        // Create a min-heap to store elements
        PriorityQueue<Integer> heap = new PriorityQueue<>();

        // Add elements from each list
        for (LinkedList<Integer> list : lists) {
            if (list != null) {
                for (Integer element : list) {
                    heap.offer(element);
                }
            }
        }

        // Extract elements from the heap and add to result list
        LinkedList<Integer> result = new LinkedList<>();
        while (!heap.isEmpty()) {
            result.add(heap.poll());
        }

        // Ensure the result has at least 10 elements
        if (result.size() < 10) {
            throw new IllegalArgumentException("Result list must have at least 10 elements");
        }

        // Output the result
        System.out.println("Merged sorted list: " + result);
    }
}
