)

type StudentGrade struct {
	Name  string
	Grade int
}

type GradeStack struct {
	grades []StudentGrade
}

func NewGradeStack() *GradeStack {
	return &GradeStack{}
}

func (s *GradeStack) Push(name string, grade int) error {
	if name == "" || grade < 0 || grade > 100 {
		return errors.New("invalid student name or grade")
	}
	if len(s.grades) >= 2000 {
		return errors.New("stack exceeds maximum size of 2000 records")
	}
	if len(s.grades) > 0 && s.grades[len(s.grades)-1].Name == name {
		return errors.New("student name already at the top of the stack")
	}
	s.grades = append(s.grades, StudentGrade{name, grade})
	return nil
}

func (s *GradeStack) UpdateTopName(name string) error {
	if len(s.grades) == 0 {
		return errors.New("stack is empty")
	}
	if s.grades[len(s.grades)-1].Name == name {
		return nil
	}
	return errors.New("student name does not match top of the stack")
}

func (s *GradeStack) Pop() error {
	if len(s.grades) == 0 {
		return errors.New("stack is empty")
	}
	s.grades = s.grades[:len(s.grades)-1]
	return nil
}

func (s *GradeStack) GetAll() []StudentGrade {
	return s.grades
}

func main() {
	stack := NewGradeStack()

	// Example usage
	if err := stack.Push("Alice", 85); err != nil {
		fmt.Println("Error pushing:", err)
	}
	if err := stack.Push("Bob", 90); err != nil {
		fmt.Println("Error pushing:", err)
	}
	if err := stack.Push("Alice", 95); err != nil {
		fmt.Println("Error pushing:", err)
	}
	if err := stack.Pop(); err != nil {
		fmt.Println("Error popping:", err)
	}

	grades := stack.GetAll()
	fmt.Println("All grades:", grades)
}

