use std::collections::HashSet;

fn max_sum_non_adjacent(nums: &[i32]) -> i32 {
    if nums.is_empty() {
        return 0;
    }

    let mut dp = vec![0; nums.len()];
    let mut hash_set = HashSet::new();

    // Initialize with the first element
    dp[0] = nums[0];
    hash_set.insert(dp[0]);

    // Iterate through the array
    for i in 1..nums.len() {
        let current = nums[i];
        let mut max_sum = 0;

        // Check if previous sum is valid
        if hash_set.contains(&dp[i - 1]) {
            max_sum = dp[i - 1];
        }

        // Add current element if it's not adjacent to previous
        if i > 1 && !hash_set.contains(&dp[i - 2]) {
            max_sum += current;
        }

        dp[i] = max_sum;
        hash_set.insert(dp[i]);
    }

    dp[nums.len() - 1]
}

fn main() {
    let nums = vec![2, 4, 5, 3, 1, 6];
    let result = max_sum_non_adjacent(&nums);
    println!("Maximum sum: {}", result);
