        // Check if current element can be added (if previous is not added)
        if i > 1 && !hash_set.contains(&dp[i - 2]) {
            max_sum = dp[i - 2];
        }

        // Update dp and hash_set
        dp[i] = max_sum + current;
        hash_set.insert(dp[i]);

        // Ensure hash_set does not exceed capacity
        if hash_set.len() > 750 {
            hash_set.drain();
        }
    }

    dp[nums.len() - 1]
}

fn main() {
    // Example usage
    let nums = vec![1, 2, 3, 4, 5];
