fn max_sum_non_adjacent(arr: &[i32]) -> i32 {
    if arr.is_empty() {
        return 0;
    }

    let mut dp = vec![0; arr.len()];
    let mut hash_set = HashSet::with_capacity(750);

    // Initialize the first element
    dp[0] = arr[0];
    hash_set.insert(dp[0]);

    // Iterate through the array
    for i in 1..arr.len() {
        let current = arr[i];
        let mut new_dp = vec![0; arr.len()];
        new_dp[i] = current;

        // Check previous elements
        for j in 0..i {
            if dp[j] != 0 && !hash_set.contains(&dp[j]) {
                new_dp[i] = dp[j] + current;
                hash_set.insert(dp[j] + current);
            }
        }

        dp = new_dp;
        hash_set.retain(|&x| x != 0);
    }

    dp[arr.len() - 1]
}

fn main() {
    // Example usage
    let arr = [1, 2, 3, 4, 5];
    let result = max_sum_non_adjacent(&arr);
    println!("Maximum sum: {}", result);
