        String processedInput = input.toLowerCase().replaceAll("[^a-z]", " ");

        String[] words = processedInput.split("\\s+");
        int uniqueWords = 0;

        for (String word : words) {
            if (!word.isEmpty()) {
                String cleanedWord = word.replaceAll("[^a-z]", "");
                if (!cleanedWord.isEmpty()) {
                    if (wordMap.containsKey(cleanedWord)) {
                        wordMap.put(cleanedWord, wordMap.get(cleanedWord) + 1);
                    } else {
                        wordMap.put(cleanedWord, 1);
                        uniqueWords++;
                    }
                    if (uniqueWords > 20) {
                        return null;
                    }
                }
            }
        }

        if (wordMap.size() > 10000) {
            return null;
        }

        return wordMap;
    }
}
