public class WordFrequency {
    public static Map<String, Integer> getWordFrequency(String input) {
        // Case-insensitive processing
        input = input.toLowerCase();

        // Remove punctuation
        StringBuilder cleaned = new StringBuilder();
        for (char c : input.toCharArray()) {
            if (Character.isLetter(c)) {
                cleaned.append(c);
            }
        }
        String cleanedInput = cleaned.toString();

        // Initialize HashMap
        Map<String, Integer> frequencyMap = new HashMap<>();

        // Process each word
        String[] words = cleanedInput.split("\\s+");
        for (String word : words) {
            if (!word.isEmpty()) {
                String key = word;
                frequencyMap.put(key, frequencyMap.getOrDefault(key, 0) + 1);
            }
        }

        // Check for more than 20 unique words
        if (frequencyMap.size() > 20) {
            throw new IllegalArgumentException("More than 20 unique words found.");
        }

        // Check for exceeding 10,000 entries
        if (frequencyMap.size() > 10000) {
            return null;
        }

        return frequencyMap;
    }
