#include <iostream>
#include <unordered_map>
#include <vector>
#include <string>
#include <stdexcept>

#define MAX_FLIGHTS 300

class Flight {
public:
    std::string flightID;
    int totalSeats;
    int bookedSeats;

    Flight(std::string id, int seats)
        : flightID(id), totalSeats(seats), bookedSeats(0) {}

    void bookSeat() {
        if (bookedSeats >= totalSeats) {
            throw std::runtime_error("Error: Flight is overbooked.");
        }
        bookedSeats++;
    }

    void cancelSeat() {
        if (bookedSeats <= 0) {
            throw std::runtime_error("Error: No seats to cancel.");
        }
        bookedSeats--;
    }

    int getAvailableSeats() const {
        return totalSeats - bookedSeats;
    }
};

class Airline {
public:
    std::string name;
    std::vector<Flight> flights;

    Airline(std::string name) : name(name) {}

    void addFlight(std::string flightID, int seats) {
        if (flights.size() >= MAX_FLIGHTS) {
            throw std::runtime_error("Error: Maximum flights limit reached for airline.");
        }
        flights.emplace_back(flightID, seats);
    }

    Flight& getFlight(std::string flightID) {
        for (auto& flight : flights) {
            if (flight.flightID == flightID) {
                return flight;
            }
        }
        throw std::runtime_error("Error: Flight not found.");
    }
};

class FlightReservationSystem {
private:
    std::unordered_map<std::string, Airline> airlines;

public:
    void addAirline(std::string airlineName) {
        airlines.emplace(airlineName, Airline(airlineName));
    }

    void addFlightToAirline(std::string airlineName, std::string flightID, int seats) {
        if (airlines.find(airlineName) == airlines.end()) {
            throw std::runtime_error("Error: Airline not found.");
        }
        airlines[airlineName].addFlight(flightID, seats);
    }

    void bookSeat(std::string airlineName, std::string flightID) {
        if (airlines.find(airlineName) == airlines.end()) {
            throw std::runtime_error("Error: Airline not found.");
        }
        airlines[airlineName].getFlight(flightID).bookSeat();
    }

    void cancelSeat(std::string airlineName, std::string flightID) {
        if (airlines.find(airlineName) == airlines.end()) {
            throw std::runtime_error("Error: Airline not found.");
        }
        airlines[airlineName].getFlight(flightID).cancelSeat();
    }

    void displaySeatAvailability(std::string airlineName, std::string flightID) {
        if (airlines.find(airlineName) == airlines.end()) {
            throw std::runtime_error("Error: Airline not found.");
        }
        Flight& flight = airlines[airlineName].getFlight(flightID);
        std::cout << "Flight " << flight.flightID << " has " 
                  << flight.getAvailableSeats() << " available seats.\n";
    }
};

int main() {
    FlightReservationSystem system;

    try {
        system.addAirline("AirlineA");
        system.addFlightToAirline("AirlineA", "Flight101", 100);
        system.addFlightToAirline("AirlineA", "Flight102", 200);

        system.bookSeat("AirlineA", "Flight101");
        system.bookSeat("AirlineA", "Flight101");

        system.displaySeatAvailability("AirlineA", "Flight101");

        system.cancelSeat("AirlineA", "Flight101");
        system.displaySeatAvailability("AirlineA", "Flight101");

        system.bookSeat("AirlineA", "Flight102");
        system.displaySeatAvailability("AirlineA", "Flight102");

    } catch (const std::exception& e) {
        std::cerr << e.what() << '\n';
    }

    return 0;
}
