#include <iostream>
#include <vector>
#include <unordered_set>
#include <climits>

using namespace std;

const int MAX_GRID = 1000;

// Define the grid structure
struct Grid {
    int rows, cols;
    vector<vector<int>> grid;
};

// Function to initialize a grid with all values as -1 (unvisited)
Grid createGrid(int rows, int cols) {
    Grid grid;
    grid.rows = rows;
    grid.cols = cols;
    grid.grid = vector<vector<int>>(rows, vector<int>(cols, -1));
    return grid;
}

// Function to perform Dijkstra's algorithm with dynamic programming approach
vector<pair<int, int>> shortestPath(Grid& grid, int startRow, int startCol, int endRow, int endCol) {
    // Check if start or end is out of bounds
    if (startRow < 0 || startRow >= grid.rows || startCol < 0 || startCol >= grid.cols) {
        return {};
    }

    // Initialize distance array
    vector<vector<int>> dist(grid.rows, vector<int>(grid.cols, INT_MAX));
    vector<vector<bool>> visited(grid.rows, vector<bool>(grid.cols, false));

    // Priority queue for Dijkstra's algorithm
    priority_queue<pair<int, pair<int, int>>, vector<pair<int, pair<int, int>>>, greater<pair<int, pair<int, int>>> pq;

    // Start from the initial position
    dist[startRow][startCol] = 0;
    pq.push({0, {startRow, startCol}});

    while (!pq.empty()) {
        auto [distVal, {row, col}] = pq.top();
        pq.pop();

        // If we reached the destination, break early
        if (row == endRow && col == endCol) {
            break;
        }

        // Skip if already visited
        if (visited[row][col]) {
            continue;
        }

        // Mark as visited
        visited[row][col] = true;

        // Explore neighbors
        vector<pair<int, int>> directions = {{-1, 0}, {1, 0}, {0, -1}, {0, 1}};
        for (auto [dr, dc] : directions) {
            int newRow = row + dr;
            int newCol = col + dc;

            // Check if neighbor is within bounds and not visited
            if (newRow >= 0 && newRow < grid.rows && newCol >= 0 && newCol < grid.cols && !visited[newRow][newCol]) {
                // Check if the cell is accessible (not blocked)
                if (grid.grid[newRow][newCol] != -1) {
                    int newDist = distVal + 1;
                    if (newDist < dist[newRow][newCol]) {
                        dist[newRow][newCol] = newDist;
                        pq.push({newDist, {newRow, newCol}});
                    }
                }
            }
        }
    }

    // Reconstruct path using distance array
    vector<pair<int, int>> path;
    int currentRow = endRow, currentCol = endCol;
    while (currentRow != startRow || currentCol != startCol) {
        path.push_back({currentRow, currentCol});
        int minDist = INT_MAX;
        int minRow = -1, minCol = -1;
        for (auto [dr, dc] : directions) {
            int newRow = currentRow + dr;
            int newCol = currentCol + dc;
            if (newRow >= 0 && newRow < grid.rows && newCol >= 0 && newCol < grid.cols && dist[newRow][newCol] == dist[currentRow][currentCol] - 1) {
                if (minDist == dist[newRow][newCol]) {
                    // Choose any valid direction (for simplicity, choose first one)
                    minRow = newRow;
                    minCol = newCol;
                    break;
                } else {
                    minDist = dist[newRow][newCol];
                    minRow = newRow;
                    minCol = newCol;
                }
            }
        }
        currentRow = minRow;
        currentCol = minCol;
    }
    path.push_back({currentRow, currentCol});

    // Reverse the path to get it from start to end
    reverse(path.begin(), path.end());

    return path;
}

int main() {
    int rows, cols;
    cout << "Enter number of rows and columns: ";
    cin >> rows >> cols;

    Grid grid = createGrid(rows, cols);
    int startRow, startCol, endRow, endCol;
    cout << "Enter start row and column: ";
    cin >> startRow >> startCol;
    cout << "Enter end row and column: ";
    cin >> endRow >> endCol;

    vector<pair<int, int>> path = shortestPath(grid, startRow, startCol, endRow, endCol);

    if (!path.empty()) {
        cout << "Shortest path found: ";
        for (auto [r, c] : path) {
            cout << "(" << r << ", " << c << ") ";
        }
        cout << endl;
    } else {
        cout << "No path found." << endl;
    }

    return 0;
}

#include <iostream>
#include <unordered_set>
#include <vector>
#include <climits>

using namespace std;

// Define the grid size
const int MAX_GRID_SIZE = 1000;

// Define the maximum number of elements in the unordered_set
const int MAX_ELEMENTS = 500;

// Function to find the shortest path using dynamic programming
int shortestPath(int grid[MAX_GRID_SIZE][MAX_GRID_SIZE], int rows, int cols) {
    // Initialize a 2D array to store the shortest path length to each cell
    int dp[rows][cols];
    // Initialize a 2D array to store the previous cell for backtracking
    int prev[rows][cols];

    // Initialize the dp array with infinity
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            dp[i][j] = INT_MAX;
        }
    }

    // Initialize the starting cell
    dp[0][0] = 0;
    prev[0][0] = {-1, -1};

    // Use a set to track visited cells
    unordered_set<pair<int, int>> visited;

    // Use a queue for BFS
    vector<pair<int, int>> queue;
    queue.push_back({0, 0});

    while (!queue.empty()) {
        pair<int, int> current = queue.front();
        queue.erase(queue.begin());

        // Check if we have reached the destination
        if (current.first == rows - 1 && current.second == cols - 1) {
            break;
        }

        // Get the current cell's neighbors
        vector<pair<int, int>> neighbors;
        if (current.first > 0) neighbors.push_back({current.first - 1, current.second});
        if (current.second > 0) neighbors.push_back({current.first, current.second - 1});

        // Check each neighbor
        for (pair<int, int> neighbor : neighbors) {
            int new_row = neighbor.first;
            int new_col = neighbor.second;

            // Check if the neighbor is within bounds and not visited
            if (new_row >= 0 && new_row < rows && new_col >= 0 && new_col < cols && !visited.count({new_row, new_col})) {
                // Update the dp array
                if (dp[new_row][new_col] > dp[current.first][current.second] + 1) {
                    dp[new_row][new_col] = dp[current.first][current.second] + 1;
                    prev[new_row][new_col] = {current.first, current.second};
                    queue.push_back({new_row, new_col});
                    visited.insert({new_row, new_col});
                }
            }
        }
    }

    // Reconstruct the path
    vector<pair<int, int>> path;
    int row = rows - 1, col = cols - 1;
    while (row != 0 || col != 0) {
        path.push_back({row, col});
        if (prev[row][col].first != -1) {
            row = prev[row][col].first;
            col = prev[row][col].second;
        } else {
            break;
        }
    }
    path.push_back({row, col});

    // Output the path
    cout << "Shortest path: ";
    for (auto p : path) {
        cout << "(" << p.first << ", " << p.second << ") ";
    }
    cout << endl;

    return dp[rows - 1][cols - 1];
}

