package main

import (
	"buffer"
	"errors"
	"log"
	"sync"
)

const MaxEntries = 1000

type TemperatureProcessor struct {
	mu       sync.Mutex
	buffer   *buffer.Buffer
	log      *log.Logger
}

func NewTemperatureProcessor(logger *log.Logger) *TemperatureProcessor {
	return &TemperatureProcessor{
		buffer: buffer.NewBuffer(MaxEntries),
		log:    logger,
	}
}

func (tp *TemperatureProcessor) AddTemperature(temp float64) error {
	tp.mu.Lock()
	defer tp.mu.Unlock()

	if tp.buffer.Len() >= MaxEntries {
		return errors.New("buffer overflow: maximum capacity reached")
	}

	tp.buffer.Append(temp)
	tp.log.Println("Temperature added:", temp)
	tp.computeMovingAverage()

	return nil
}

func (tp *TemperatureProcessor) computeMovingAverage() {
	if tp.buffer.Len() == 0 {
		tp.log.Println("No data to compute moving average")
		return
	}

	var sum float64
	bufferData := tp.buffer.Data()
	for _, temp := range bufferData {
		sum += temp.(float64)
	}
	movingAvg := sum / float64(len(bufferData))
	tp.log.Printf("Computed moving average: %.2f\n", movingAvg)
}

func main() {
	logger := log.New(log.Writer(), "TemperatureProcessor: ", log.LstdFlags|log.Lshortfile)
	tp := NewTemperatureProcessor(logger)

	// Example usage: simulate adding temperature data
	for i := 0; i < 1005; i++ {
		temp := float64(i)
		if err := tp.AddTemperature(temp); err != nil {
			logger.Println("Error while adding temperature:", err)
		}
	}
}
