type TemperatureData struct {
	Value float64
}

type Buffer struct {
	data []TemperatureData
	mu   sync.Mutex
}

func (b *Buffer) Add(data TemperatureData) error {
	b.mu.Lock()
	defer b.mu.Unlock()
	if len(b.data) >= 1000 {
		return errors.New("buffer overflow")
	}
	b.data = append(b.data, data)
	return nil
}

func (b *Buffer) GetAverage() (float64, error) {
	if len(b.data) == 0 {
		return 0, errors.New("no data available")
	}
	sort.Slice(b.data, func(i, j int) bool { return b.data[i].Value < b.data[j].Value })
	average := 0.0
	for i := 0; i < len(b.data); i++ {
		average += b.data[i].Value
	}
	average /= len(b.data)
	return average, nil
}

func main() {
	buffer := &Buffer{}
	for i := 0; i < 1000; i++ {
		data := TemperatureData{Value: float64(i)}
		if err := buffer.Add(data); err != nil {
			log.Printf("Error adding data: %v", err)
		}
	}
	average, err := buffer.GetAverage()
	if err != nil {
		log.Printf("Error getting average: %v", err)
	} else {
		fmt.Printf("Average temperature: %.2f\n", average)
	}
}

