int maxSubarraySum(const std::vector<int>& nums) {
    if (nums.empty()) {
        return 0;
    }

    std::stack<int> stack;
    int maxSum = nums[0];
    int currentSum = nums[0];

    for (size_t i = 1; i < nums.size(); ++i) {
        if (currentSum + nums[i] > nums[i]) {
            currentSum += nums[i];
        } else {
            stack.push(currentSum);
            currentSum = nums[i];
        }
        maxSum = std::max(maxSum, currentSum);
    }

    stack.push(currentSum);
    maxSum = std::max(maxSum, currentSum);

    return maxSum;
}

