    std::priority_queue<std::tuple<int, int, int>, std::vector<std::tuple<int, int, int>>, std::greater<>> minHeap;
    std::vector<int> mergedArray;

    // Initialize a heap with the first element of each array
    for (int i = 0; i < arrays.size(); ++i) {
        if (!arrays[i].empty()) {
            minHeap.emplace(arrays[i][0], i, 0);
        }
    }

    // Process the heap and merge arrays
    while (!minHeap.empty()) {
        auto [value, arrayIndex, elementIndex] = minHeap.top();
        minHeap.pop();
        mergedArray.push_back(value);

        if (elementIndex + 1 < arrays[arrayIndex].size()) {
            minHeap.emplace(arrays[arrayIndex][elementIndex + 1], arrayIndex, elementIndex + 1);
        }
    }

    return mergedArray;
}

