import java.util.PriorityQueue;

public class TaskProcessor {

    private static class Task implements Comparable<Task> {
        int priority;
        int duration; // in milliseconds

        public Task(int priority, int duration) {
            this.priority = priority;
            this.duration = duration;
        }

        @Override
        public int compareTo(Task other) {
            return Integer.compare(other.priority, this.priority); // Higher priority first
        }
    }

    public void processTasks(PriorityQueue<Task> taskQueue) {
        if (taskQueue == null || taskQueue.isEmpty()) {
            System.out.println("Task queue is empty.");
            return;
        }

        long startTime = System.currentTimeMillis();

        while (!taskQueue.isEmpty()) {
            Task task = taskQueue.poll(); // Retrieves and removes the highest-priority task
            try {
                Thread.sleep(task.duration); // Simulate task execution by sleeping for its duration
            } catch (InterruptedException e) {
                System.out.println("Task interrupted: " + e.getMessage());
            }
        }

        long endTime = System.currentTimeMillis();
        System.out.println("Total execution time: " + (endTime - startTime) + " milliseconds.");
    }

    public static void main(String[] args) {
        PriorityQueue<Task> taskQueue = new PriorityQueue<>();

        // Populate taskQueue (max size 100)
        for (int i = 1; i <= 100; i++) {
            taskQueue.offer(new Task(i % 10, i * 10)); // Example with priority and duration
        }

        TaskProcessor processor = new TaskProcessor();
        processor.processTasks(taskQueue);
    }
}
