public class TaskProcessor {
    private Queue<Task> taskQueue;
    private AtomicInteger totalExecutionTime = new AtomicInteger(0);

    public TaskProcessor() {
        taskQueue = new PriorityQueue<>();
    }

    public void add(Task task) {
        if (taskQueue.size() >= 100) {
            throw new IllegalStateException("Maximum 100 tasks allowed.");
        }
        taskQueue.add(task);
    }

    public Task poll() {
        if (taskQueue.isEmpty()) {
            throw new IllegalStateException("Queue is empty.");
        }
        Task task = taskQueue.poll();
        totalExecutionTime.addAndGet(task.getDuration());
        return task;
    }

    public Task peek() {
        if (taskQueue.isEmpty()) {
            throw new IllegalStateException("Queue is empty.");
        }
        return taskQueue.peek();
    }

    public void clear() {
        taskQueue.clear();
    }

    public long getTotalExecutionTime() {
        return totalExecutionTime.get();
    }

    // Task class with required properties
    static class Task {
        private final int priority;
        private final long duration;

        public Task(int priority, long duration) {
            this.priority = priority;
            this.duration = duration;
        }

        public int getPriority() {
            return priority;
        }

        public long getDuration() {
            return duration;
        }
    }
