};

class BookCatalog {
private:
    map<int, Book> catalog; // Key: genre, Value: Book
    int maxEntries = 500;

public:
    void insertBook(int genre, string title, string author, double price, int quantity) {
        if (catalog.size() >= maxEntries) {
            cout << "Error: Catalog is full." << endl;
            return;
        }
        catalog[genre] = Book(title, author, price, quantity, genre);
    }

    Book getBook(int genre) {
        auto it = catalog.find(genre);
        if (it != catalog.end()) {
            return it->second;
        }
        return Book("", "", 0.0, 0, -1);
    }

    void applyDiscount(int genre, double rate) {
        auto it = catalog.find(genre);
        if (it != catalog.end()) {
            it->second.isDiscounted = true;
            it->second.discountRate = rate;
        }
    }

    double calculateTotalPrice(int genre, int quantity) {
        auto it = catalog.find(genre);
        if (it != catalog.end()) {
            return it->second.price * quantity;
        }
        return 0.0;
    }

    void displayCatalog() {
        for (const auto& entry : catalog) {
            cout << "Genre: " << entry.first << ", Title: " << entry.second.title
                 << ", Author: " << entry.second.author << ", Price: $" << entry.second.price
                 << ", Quantity: " << entry.second.quantity << endl;
        }
    }
