bool compareByPrice(const Product& p1, const Product& p2) {
    return p1.price < p2.price;
}

// Stack-based product map
class ProductMap {
private:
    stack<Product> productStack;
    map<string, Product> productCatalog;

public:
    // Insertion of product
    void insertProduct(const string& name, double price, int quantity) {
        productCatalog[name] = {name, price, quantity};
        productStack.push(productCatalog[name]);
    }

    // Retrieval of product
    Product retrieveProduct(const string& name) {
        auto it = productCatalog.find(name);
        if (it != productCatalog.end()) {
            return it->second;
        }
        return Product{};
    }

    // Get all products
    vector<Product> getAllProducts() {
        vector<Product> products;
        while (!productStack.empty()) {
            products.push_back(productStack.top());
            productStack.pop();
        }
        return products;
    }

    // Custom sorting of products by price
    void sortProductsByPrice() {
        vector<Product> products = getAllProducts();
        sort(products.begin(), products.end(), compareByPrice);
        for (auto& prod : products) {
            productStack.push(prod);
        }
    }
};

