        return value > other.value;
    }
};

void mergeSortedArrays(const vector<vector<int>>& arrays, vector<int>& mergedArray) {
    priority_queue<ArrayElement, vector<ArrayElement>, greater<>> minHeap;

    // Initialize heap with the first element of each array
    for (int i = 0; i < arrays.size(); ++i) {
        if (!arrays[i].empty()) {
            minHeap.push({arrays[i][0], i, 0});
        }
    }

    while (!minHeap.empty()) {
        ArrayElement current = minHeap.top();
        minHeap.pop();
        mergedArray.push_back(current.value);

        // Move to the next element in the array
        if (current.elementIndex + 1 < arrays[current.arrayIndex].size()) {
            minHeap.push({arrays[current.arrayIndex][current.elementIndex + 1], current.arrayIndex, current.elementIndex + 1});
        }
    }
}

