using namespace std;

// Function to merge sorted arrays using min-heap
vector<int> mergeSortedArrays(vector<vector<int>> arrays) {
    priority_queue<pair<int, vector<int>>, vector<pair<int, vector<int>>, greater<pair<int, vector<int>> > > heap;

    // Initialize the heap with the first element of each array
    for (auto& arr : arrays) {
        if (!arr.empty()) {
            heap.push({arr[0], arr});
        }
    }

    vector<int> result;

    while (!heap.empty()) {
        auto top = heap.top();
        heap.pop();

        result.push_back(top.first);

        // If the array has more elements, add the next element to the heap
        if (top.second.size() > 1) {
            heap.push({top.second[1], top.second});
        }
    }

    return result;
}

int main(int argc, char* argv[]) {
    vector<vector<int>> arrays;

    // Parse command-line arguments
    for (int i = 1; i < argc; i++) {
        string arg = argv[i];
        istringstream iss(arg);
        int num;
        iss >> num;
        vector<int> arr;
        for (int j = 0; j < num; j++) {
            int val;
            iss >> val;
