#include <sstream>

using namespace std;

// Function to merge sorted arrays using a min-heap
vector<int> mergeSortedArrays(vector<vector<int>> arrays) {
    priority_queue<int, vector<int>, greater<int>> pq;

    // Initialize the heap with elements from the first array
    for (int num : arrays[0]) {
        pq.push(num);
    }

    // Process remaining elements from other arrays
    for (size_t i = 1; i < arrays.size(); ++i) {
        for (int num : arrays[i]) {
            pq.push(num);
        }
    }

    // Extract elements from the heap and store in result
    vector<int> result;
    while (!pq.empty()) {
        result.push_back(pq.top());
        pq.pop();
    }

    return result;
}

// Function to read input from command line or file
vector<vector<int>> readInput(const string& filename) {
    vector<vector<int>> arrays;
    ifstream file(filename);

    if (!file.is_open()) {
        cerr << "Error: Could not open file." << endl;
        return arrays;
    }

    string line;
    while (getline(file, line)) {
        istringstream iss(line);
        vector<int> arr;
        int num;
        while (iss >> num) {
            arr.push_back(num);
        }
        if (!arr.empty()) {
            arrays.push_back(arr);
        }
    }

    return arrays;
}

// Function to write output to console or file
void writeOutput(const vector<int>& merged, const string& filename) {
    ofstream file(filename);
    if (file.is_open()) {
        for (int num : merged) {
            file << num << " ";
        }
        file << endl;
    } else {
        cerr << "Error: Could not open file for writing." << endl;
    }
}

int main(int argc, char* argv[]) {
    // Check command line arguments
    if (argc < 2) {
        cout << "Usage: " << argv[0] << " <filename>" << endl;
        return 1;
    }

    string filename = argv[1];

    // Read input from file
    vector<vector<int>> arrays = readInput(filename);

    // Merge the arrays
    vector<int> merged = mergeSortedArrays(arrays);

    // Output the result
    writeOutput(merged, "merged_output.txt");

    return 0;
}

