#include <iostream>
#include <deque>
#include <mutex>
#include <stdexcept>
#include <algorithm>
#include <vector>
#include <string>

class Employee {
public:
    Employee(const std::string& name, int age) : name(name), age(age) {}

    std::string name;
    int age;
};

class EmployeeComparator {
public:
    bool operator()(const Employee& e1, const Employee& e2) const {
        if (e1.age != e2.age) {
            return e1.age < e2.age;
        }
        return e1.name < e2.name;
    }
};

class ThreadSafeDeque {
private:
    std::deque<Employee> deque;
    mutable std::mutex mtx;

public:
    void push_back(const Employee& emp) {
        std::lock_guard<std::mutex> lock(mtx);
        deque.push_back(emp);
    }

    Employee pop_back() {
        std::lock_guard<std::mutex> lock(mtx);
        if (deque.empty()) {
            throw std::runtime_error("Deque is empty");
        }
        Employee emp = deque.back();
        deque.pop_back();
        return emp;
    }

    bool empty() const {
        std::lock_guard<std::mutex> lock(mtx);
        return deque.empty();
    }

    size_t size() const {
        std::lock_guard<std::mutex> lock(mtx);
        return deque.size();
    }

    void clear() {
        std::lock_guard<std::mutex> lock(mtx);
        deque.clear();
    }

    // Custom comparator for sorting
    static bool compareByAge(const Employee& e1, const Employee& e2) {
        return e1.age < e2.age;
    }

    static bool compareByName(const Employee& e1, const Employee& e2) {
        return e1.name < e2.name;
    }

    // Sort the deque using custom comparators
    void sortByAge() {
        std::lock_guard<std::mutex> lock(mtx);
        std::vector<Employee> temp;
        std::copy(deque.begin(), deque.end(), std::back_inserter(temp));
        std::sort(temp.begin(), temp.end(), EmployeeComparator());
        deque = temp;
    }

    void sortByName() {
        std::lock_guard<std::mutex> lock(mtx);
        std::vector<Employee> temp;
        std::copy(deque.begin(), deque.end(), std::back_inserter(temp));
        std::sort(temp.begin(), temp.end(), EmployeeComparator());
        deque = temp;
    }

    // Check if deque exceeds capacity
    bool isWithinCapacity(size_t capacity) const {
        std::lock_guard<std::mutex> lock(mtx);
        return deque.size() <= capacity;
    }
};

int main() {
    ThreadSafeDeque deque;

    try {
        // Example employee data
        Employee emp1("Alice", 30);
        Employee emp2("Bob", 25);
        Employee emp3("Charlie", 35);
        Employee emp4("David", 28);

        // Add employees to deque
        deque.push_back(emp1);
        deque.push_back(emp2);
        deque.push_back(emp3);
        deque.push_back(emp4);

        // Sort by age
        deque.sortByAge();

        // Sort by name
        deque.sortByName();

        // Check capacity
        if (!deque.isWithinCapacity(800)) {
            std::cerr << "Deque exceeds capacity of 800." << std::endl;
        }

        // Print results
        std::cout << "Sorted by age:" << std::endl;
        for (const auto& emp : deque) {
            std::cout << emp.name << ", " << emp.age << std::endl;
        }

        std::cout << "Sorted by name:" << std::endl;
        for (const auto& emp : deque) {
            std::cout << emp.name << ", " << emp.age << std::endl;
        }
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }

    return 0;
}

