    while let Some(word) = word_queue.pop_front() {
        if let Some(count) = word_counts.get_mut(word) {
            *count += 1;
        } else {
            word_counts.insert(word, 1);
        }
    }

    // Limit hash map size to 10,000 elements
    if word_counts.len() > 10_000 {
        let removed: Vec<_> = word_counts.drain(&mut Vec::new()).collect();
        println!("Removed {} entries from the hash map.", removed.len());
    }

    // Display most frequent words
    let mut sorted_words: Vec<(String, usize)> = word_counts
        .into_iter()
        .rev()
        .take(10_000)
        .collect();

    println!("Most frequent words:");
