fn main() {
    let file_path = "large_text_file.txt";
    let mut word_freq_map: HashMap<String, usize> = HashMap::new();
    let mut word_count = 0;

    // Open the file and read lines
    let reader = BufReader::new(File::open(file_path).expect("Failed to open file"));
    for line in reader.lines() {
        let line_str = line.expect("Failed to read line");
        let tokens: VecDeque<&str> = line_str.split_whitespace().collect();
        for token in tokens {
            // Tokenize and process case-insensitively
            let cleaned_token = token.to_lowercase();
            // Remove punctuation
            let mut cleaned = String::new();
            for c in cleaned_token.chars() {
                if c.is_alphabetic() || c.is_digit(10) {
                    cleaned.push(c);
                }
            }
            if !cleaned.is_empty() {
                let key = cleaned;
                // Insert into map
                if let Some(count) = word_freq_map.get_mut(&key) {
                    *count += 1;
                } else {
                    word_freq_map.insert(key, 1);
                }
                word_count += 1;
            }
        }
    }

    // Check if map size exceeds 10,000
    if word_freq_map.len() > 10_000 {
        // Remove the least frequent words
        let mut sorted: Vec<(String, usize)> = word_freq_map.iter().cloned().collect();
        sorted.sort_by(|a, b| b.1.cmp(&a.1));
        let mut new_map: HashMap<String, usize> = HashMap::new();
        for (word, count) in &sorted {
            if new_map.len() < 10_000 {
                new_map.insert(word.clone(), *count);
            }
        }
        word_freq_map = new_map;
    }

    // Output the most common words in hierarchical structure
    let mut output = String::new();
    let mut sorted: Vec<(String, usize)> = word_freq_map.iter().cloned().collect();
    sorted.sort_by(|a, b| b.1.cmp(&a.1));
    for (word, count) in &sorted {
        output.push_str(&format!("{}: {}\n", word, count));
    }

    println!("{}", output);
}
