use std::collections::{HashMap, LinkedList};
use std::time::{SystemTime, UNIX_EPOCH};

#[derive(Debug, Clone)]
struct Message {
    id: u64,
    timestamp: u64,
    content: String,
}

#[derive(Debug)]
enum QueueError {
    Overflow,
    NotFound,
    EmptyQueue,
}

struct MessageQueue {
    messages: LinkedList<Message>,
    index: HashMap<u64, LinkedList<Message>::Iter<'static>>,
    max_size: usize,
}

impl MessageQueue {
    fn new(max_size: usize) -> Self {
        MessageQueue {
            messages: LinkedList::new(),
            index: HashMap::new(),
            max_size,
        }
    }

    fn enqueue(&mut self, id: u64, content: String) -> Result<(), QueueError> {
        if self.messages.len() == self.max_size {
            return Err(QueueError::Overflow);
        }
        let timestamp = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap()
            .as_secs();
        let message = Message {
            id,
            timestamp,
            content,
        };
        self.messages.push_back(message);
        Ok(())
    }

    fn dequeue(&mut self) -> Result<Message, QueueError> {
        match self.messages.pop_front() {
            Some(msg) => {
                self.index.remove(&msg.id);
                Ok(msg)
            }
            None => Err(QueueError::EmptyQueue),
        }
    }

    fn lookup(&self, id: u64) -> Result<&Message, QueueError> {
        for msg in self.messages.iter() {
            if msg.id == id {
                return Ok(msg);
            }
        }
        Err(QueueError::NotFound)
    }
}

fn main() {
    let mut queue = MessageQueue::new(500);

    match queue.enqueue(1, String::from("First message")) {
        Ok(_) => println!("Message enqueued."),
        Err(e) => println!("Error: {:?}", e),
    }

    match queue.lookup(1) {
        Ok(msg) => println!("Message found: {:?}", msg),
        Err(e) => println!("Error: {:?}", e),
    }

    match queue.dequeue() {
        Ok(msg) => println!("Dequeued: {:?}", msg),
        Err(e) => println!("Error: {:?}", e),
    }
}
