}

impl MessageQueue {
    fn new(max_size: usize, expiration_time: Duration) -> Self {
        MessageQueue {
            queue: Mutex::new(LinkedList::new()),
            max_size,
            expiration_time,
        }
    }

    fn push(&mut self, message: Message) -> Result<(), String> {
        if self.queue.lock().unwrap().len() >= self.max_size {
            return Err("Queue is full".to_string());
        }

        self.queue.lock().unwrap().push_back(message);
        thread::spawn(move || {
            let mut queue = self.queue.lock().unwrap();
            let now = std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .unwrap()
                .as_nanos() as usize;
            let expiration_time = self.expiration_time.as_nanos() as usize;
            let mut iter = queue.iter_mut();
            while let Some(msg) = iter.next() {
                if msg.timestamp > now - expiration_time {
                    continue;
                }
                msg.timestamp = now;
            }
        });
        Ok(())
    }

    fn pop(&mut self) -> Result<Message, String> {
        if self.queue.lock().unwrap().is_empty() {
            return Err("Queue is empty".to_string());
        }

        let mut queue = self.queue.lock().unwrap();
        let msg = queue.pop_front().unwrap();
        thread::spawn(move || {
            let mut queue = self.queue.lock().unwrap();
            let now = std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .unwrap()
                .as_nanos() as usize;
            let expiration_time = self.expiration_time.as_nanos() as usize;
            let mut iter = queue.iter_mut();
            while let Some(msg) = iter.next() {
                if msg.timestamp > now - expiration_time {
                    continue;
                }
                msg.timestamp = now;
            }
        });
        Ok(msg)
    }

    fn lookup(&self, id: &str) -> Option<Message> {
        let queue = self.queue.lock().unwrap();
        queue.iter().find(|msg| msg.id == id).cloned()
    }
}

fn main() {
    let queue = MessageQueue::new(500, Duration::from_secs(30));
    let mut msg1 = Message::new("1", "Hello");
    let mut msg2 = Message::new("2", "World");

    queue.push(msg1).unwrap();
    queue.push(msg2).unwrap();

    let msg1 = queue.pop().unwrap();
    let msg2 = queue.pop().unwrap();

    println!("Popped messages: {}", msg1.id, msg2.id);

    if let Some(msg) = queue.lookup("1") {
        println!("Found message with ID: {}", msg.id);
    } else {
        println!("Message not found");
    }
}
