use std::collections::LinkedList;
use std::sync::{Mutex, MutexGuard};
use std::time::Duration;
use std::thread;

struct Message {
    id: String,
    timestamp: std::time::SystemTime,
    content: String,
}

struct Queue {
    queue: Mutex<LinkedList<Message>>,
    max_size: usize,
    last_time: std::time::SystemTime,
}

impl Queue {
    fn new(max_size: usize) -> Self {
        Queue {
            queue: Mutex::new(LinkedList::new()),
            max_size,
            last_time: std::time::SystemTime::now(),
        }
    }

    fn push(&mut self, message: Message) {
        let mut queue = self.queue.lock().unwrap();
        if queue.len() == self.max_size {
            // Discard messages older than 30 seconds
            let now = std::time::SystemTime::now();
            let threshold = self.last_time + Duration::from_secs(30);
            let mut guard = queue.lock().unwrap();
            for i in (0..guard.len()).rev() {
                if now >= threshold {
                    guard.remove(i);
                } else {
                    break;
                }
            }
        }
        queue.push_back(message);
        self.last_time = now;
    }

    fn pop(&mut self) -> Option<Message> {
        let mut queue = self.queue.lock().unwrap();
        if queue.len() > 0 {
            let msg = queue.pop_front();
            if msg.is_some() {
                return msg;
            }
        }
        None
    }

    fn get_by_id(&self, id: &str) -> Option<Message> {
        let queue = self.queue.lock().unwrap();
        for msg in queue.iter() {
            if msg.id == *id {
                return Some(msg.clone());
            }
        }
        None
    }

    fn is_over_capacity(&self) -> bool {
        self.queue.lock().unwrap().len() >= self.max_size
    }
}

