    CinemaSeat() {}

    // Add a reservation
    void reserve(string seatNumber, string customerName) {
        if (bookings.size() >= MAX_BOOKINGS) {
            throw runtime_error("Cannot reserve: Maximum bookings reached.");
        }
        bookings.push_back(customerName + " - " + seatNumber);
    }

    // Check availability
    bool isAvailable(string seatNumber) {
        for (string booking : bookings) {
            if (booking.substr(0, 6) == seatNumber) {
                return false;
            }
        }
        return true;
    }

    // Update reservation
    void updateReservation(string seatNumber, string newCustomerName) {
        for (int i = 0; i < bookings.size(); ++i) {
            if (bookings[i].substr(0, 6) == seatNumber) {
                bookings[i] = newCustomerName + " - " + seatNumber;
                break;
            }
        }
    }

    // Cancel reservation
    void cancelReservation(string seatNumber) {
        for (int i = 0; i < bookings.size(); ++i) {
            if (bookings[i].substr(0, 6) == seatNumber) {
                bookings.erase(bookings.begin() + i);
                break;
            }
        }
    }

