        self.tasks = []

    def add_task(self, task, deadline):
        """Add a task with a specific deadline."""
        heapq.heappush(self.tasks, (deadline, task))

    def update_task(self, old_task, new_task, new_deadline):
        """Update an existing task with a new deadline."""
        # Find the index of the old task
        idx = -1
        for i in range(len(self.tasks)):
            if self.tasks[i][1] == old_task:
                idx = i
                break

        if idx != -1:
            # Remove the old task
            del self.tasks[idx]

            # Add the new task
            heapq.heappush(self.tasks, (new_deadline, new_task))

    def delete_task(self, task):
        """Delete a task."""
        # Find the index of the task
        idx = -1
        for i in range(len(self.tasks)):
            if self.tasks[i][1] == task:
                idx = i
                break

        if idx != -1:
            del self.tasks[idx]

    def get_next_task(self):
        """Get the task with the closest deadline."""
        if self.tasks:
            return self.tasks[0]
        return None

    def heapify(self):
        """Ensure the priority queue is in a valid state."""
        heapq.heapify(self.tasks)

    def __len__(self):
        return len(self.tasks)

    def __str__(self):
        return str(self.tasks)
