        logOperation("remove", task);
    }

    public Task pollFirst() {
        if (tasks.isEmpty()) {
            throw new IllegalStateException("Cannot poll from empty TreeSet.");
        }
        Task task = tasks.pollFirst();
        logOperation("pollFirst", task);
        return task;
    }

    private void logOperation(String operation, Task task) {
        System.out.println("Operation: " + operation + ", Task ID: " + task.getId() + ", Priority: " + task.getPriority());
    }

    public static void main(String[] args) {
        TaskScheduler scheduler = new TaskScheduler();

        // Example tasks
        Task task1 = new Task(1, "Task A", 3);
        Task task2 = new Task(2, "Task B", 2);
        Task task3 = new Task(3, "Task C", 4);

        try {
            scheduler.addTask(task1);
            scheduler.addTask(task2);
            scheduler.addTask(task3);
            System.out.println("After adding 3 tasks: " + scheduler.tasks.size());

            scheduler.pollFirst();
            System.out.println("After pollFirst: " + scheduler.tasks.size());

            scheduler.removeTask(task1);
            System.out.println("After removing task1: " + scheduler.tasks.size());
        } catch (Exception e) {
            System.err.println("Error: " + e.getMessage());
        }
    }
}

class Task {
