#include <iostream>
#include <queue>
#include <stdexcept>

struct Item {
    std::string name;
    int urgency;

    bool operator<(const Item& other) const {
        return urgency < other.urgency;  // Higher urgency should come first
    }
};

class InventorySystem {
private:
    std::priority_queue<Item> inventoryQueue;
    static const int MAX_ITEMS = 500;

public:
    void addItem(const std::string& name, int urgency) {
        if (inventoryQueue.size() >= MAX_ITEMS) {
            throw std::runtime_error("Inventory is full, cannot add more items.");
        }
        inventoryQueue.push({name, urgency});
    }

    void removeItem() {
        if (inventoryQueue.empty()) {
            throw std::runtime_error("Cannot remove item: Inventory is empty.");
        }
        inventoryQueue.pop();
    }

    Item retrieveTopItem() {
        if (inventoryQueue.empty()) {
            throw std::runtime_error("Cannot retrieve item: Inventory is empty.");
        }
        return inventoryQueue.top();
    }

    bool isEmpty() const {
        return inventoryQueue.empty();
    }
};

int main() {
    InventorySystem storeInventory;

    try {
        storeInventory.addItem("Laptop", 5);
        storeInventory.addItem("Smartphone", 10);
        storeInventory.addItem("Headphones", 3);

        Item topItem = storeInventory.retrieveTopItem();
        std::cout << "Top item: " << topItem.name << " with urgency " << topItem.urgency << '\n';

        storeInventory.removeItem();
        topItem = storeInventory.retrieveTopItem();
        std::cout << "Top item after removal: " << topItem.name << " with urgency " << topItem.urgency << '\n';

    } catch (const std::runtime_error& e) {
        std::cerr << "Error: " << e.what() << '\n';
    }

    return 0;
}
