#include <stdexcept>

class InventoryManager {
private:
    std::priority_queue<std::string, std::vector<std::string>, std::greater<std::string>> inventoryQueue;
    static const int MAX_ITEMS = 500;

public:
    // Add an item to the queue
    void push(const std::string& item) {
        if (inventoryQueue.size() >= MAX_ITEMS) {
            throw std::overflow_error("Inventory queue is full");
        }
        inventoryQueue.push(item);
    }

    // Remove and return the highest priority item
    std::string pop() {
        if (inventoryQueue.empty()) {
            throw std::underflow_error("Inventory queue is empty");
        }
        std::string item = inventoryQueue.top();
        inventoryQueue.pop();
        return item;
    }

    // Return the highest priority item without removing it
    std::string top() {
        if (inventoryQueue.empty()) {
            throw std::underflow_error("Inventory queue is empty");
        }
        return inventoryQueue.top();
    }

    // Check if the queue is empty
    bool empty() const {
        return inventoryQueue.empty();
    }
};

int main() {
    InventoryManager manager;

    try {
        manager.push("Laptop");
        manager.push("Smartphone");
        manager.push("Tablet");
        manager.push("Headphones");
        manager.push("Monitor");

        std::cout << "Top item: " << manager.top() << std::endl;

        std::string item = manager.pop();
        std::cout << "Popped item: " << item << std::endl;

        std::cout << "Queue is empty: " << (manager.empty() ? "Yes" : "No") << std::endl;
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }

    return 0;
}

