using namespace std;

class InventoryManager {
private:
    vector<int> inventory;
    priority_queue<int> pq;

public:
    void add(int item) {
        if (inventory.size() >= 500) {
            throw runtime_error("Inventory is full");
        }
        inventory.push(item);
        pq.push(item);
    }

    void remove(int item) {
        if (inventory.size() == 0) {
            throw runtime_error("Inventory is empty");
        }
        auto it = find(inventory.begin(), inventory.end(), item);
        if (it == inventory.end()) {
            throw runtime_error("Item not found");
        }
        inventory.erase(it);
        pq.pop();
    }

    int getTop() {
        if (inventory.size() == 0) {
            throw runtime_error("Inventory is empty");
        }
        return pq.top();
    }

    void displayInventory() {
        if (inventory.size() == 0) {
            cout << "Inventory is empty" << endl;
            return;
        }
        for (int item : inventory) {
            cout << item << " ";
        }
        cout << endl;
    }
};

