#include <iostream>
#include <vector>
#include <stdexcept>
#include <algorithm>

class InventoryQueue {
private:
    std::vector<int> items;
    static const int MAX_ITEMS = 500;

public:
    InventoryQueue() {}

    void push(int item) {
        if (items.size() >= MAX_ITEMS) {
            throw std::overflow_error("Inventory queue is full");
        }
        items.push_back(item);
    }

    int pop() {
        if (items.empty()) {
            throw std::underflow_error("Inventory queue is empty");
        }
        int item = items.back();
        items.pop_back();
        return item;
    }

    int top() {
        if (items.empty()) {
            throw std::underflow_error("Inventory queue is empty");
        }
        return items.back();
    }

    bool empty() const {
        return items.empty();
    }

    int size() const {
        return items.size();
    }
};

int main() {
    InventoryQueue inventory;

    try {
        inventory.push(100);
        inventory.push(200);
        inventory.push(300);
        inventory.push(400);
        inventory.push(500);

        std::cout << "Top item: " << inventory.top() << std::endl;
        std::cout << "Item after pop: " << inventory.pop() << std::endl;

        while (!inventory.empty()) {
            std::cout << inventory.top() << std::endl;
            inventory.pop();
        }
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }

