use std::fmt;

// Define the Media enum to handle different types of media
#[derive(Debug)]
enum Media {
    Book(String, String),      // Title, Author
    Movie(String, String),     // Title, Director
    Music(String, String),     // Title, Artist
}

// Implement Display trait for Media to format output
impl fmt::Display for Media {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            Media::Book(title, author) => write!(f, "Book: '{}' by '{}'", title, author),
            Media::Movie(title, director) => write!(f, "Movie: '{}' directed by '{}'", title, director),
            Media::Music(title, artist) => write!(f, "Music: '{}' by '{}'", title, artist),
        }
    }
}

// Define the Library struct to manage the media collection
struct Library {
    collection: Vec<Media>, // Collection of Media
    limit: usize,           // Max capacity
}

impl Library {
    // Constructor for Library
    fn new(limit: usize) -> Self {
        Library {
            collection: Vec::new(),
            limit,
        }
    }

    // Add a media entry to the library
    fn add_media(&mut self, media: Media) -> Result<(), String> {
        if self.collection.len() >= self.limit {
            return Err(String::from("Error: Library is full. Cannot add more entries."));
        }
        self.collection.push(media);
        Ok(())
    }

    // Display all entries in the library
    fn display(&self) {
        for media in &self.collection {
            println!("{}", media);
        }
    }

    // Find a media entry by title
    fn find_by_title(&self, title: &str) -> Option<&Media> {
        self.collection.iter().find(|&media| match media {
            Media::Book(media_title, _) => media_title == title,
            Media::Movie(media_title, _) => media_title == title,
            Media::Music(media_title, _) => media_title == title,
        })
    }
}

fn main() {
    let mut library = Library::new(1000); // Create a library with max capacity of 1,000 entries

    // Adding entries to the library
    match library.add_media(Media::Book(String::from("Rust Programming"), String::from("Steve Klabnik"))) {
        Ok(_) => println!("Added Book"),
        Err(err) => println!("{}", err),
    }

    match library.add_media(Media::Movie(String::from("Inception"), String::from("Christopher Nolan"))) {
        Ok(_) => println!("Added Movie"),
        Err(err) => println!("{}", err),
    }

    match library.add_media(Media::Music(String::from("Bohemian Rhapsody"), String::from("Queen"))) {
        Ok(_) => println!("Added Music"),
        Err(err) => println!("{}", err),
    }

    // Display the library entries
    println!("Library Collection:");
    library.display();

    // Lookup media by title
    if let Some(media) = library.find_by_title("Inception") {
        println!("Found: {}", media);
    } else {
        println!("Media not found.");
    }

    // Attempt to add beyond the limit
    for _ in 0..1001 {
        if let Err(err) = library.add_media(Media::Music(String::from("Song Title"), String::from("Artist"))) {
            println!("{}", err);
            break;
        }
    }
}
