import os
from collections import Counter
from collections import deque

class ErrorStack:
    def __init__(self):
        self.stack = deque()

    def push(self, message):
        if len(self.stack) >= 20:
            self.stack.popleft()
        self.stack.append(message)

    def pop(self):
        if self.stack:
            return self.stack.pop()
        return None

    def is_empty(self):
        return not self.stack

def process_log_file(log_file_path):
    error_stack = ErrorStack()
    ip_counter = Counter()

    try:
        with open(log_file_path, 'r') as file:
            for line in file:
                line = line.strip()
                if not line:
                    continue
                try:
                    ip = line.split()[1]
                    ip_counter[ip] += 1
                except IndexError:
                    error_stack.push("Invalid log entry format")
    except FileNotFoundError:
        error_stack.push("File not found")
    except Exception as e:
        error_stack.push(f"Unexpected error: {str(e)}")

    if len(ip_counter) > 10000:
        error_stack.push("Exceeded maximum IP address limit of 10,000")

    return ip_counter, error_stack

def summarize_user_activities(ip_counter, error_stack):
    summary = {}
    for ip, count in ip_counter.items():
        if count > 10000:
            error_stack.push("IP address count exceeds 10,000")
        summary[ip] = count

    return summary, error_stack

def main():
    log_file_path = "log.txt"
    ip_counter, error_stack = process_log_file(log_file_path)
    summary, error_stack = summarize_user_activities(ip_counter, error_stack)

    print("User Activity Summary:")
    for ip, count in summary.items():
        print(f"IP {ip}: {count} accesses")

    print("\nError Messages:")
    for msg in error_stack:
        print(msg)

if __name__ == "__main__":
