use smallvec::SmallVec;
use std::cmp::Ordering;

#[derive(Debug, Clone)]
struct Task {
    id: usize,
    priority: i32,
    name: String,
}

impl Task {
    fn new(id: usize, priority: i32, name: String) -> Self {
        Task { id, priority, name }
    }
}

struct PriorityQueue {
    tasks: SmallVec<[Task; 200]>,
}

impl PriorityQueue {
    fn new() -> Self {
        PriorityQueue {
            tasks: SmallVec::new(),
        }
    }

    fn add_task(&mut self, task: Task) -> Result<(), &'static str> {
        if self.tasks.len() >= 200 {
            return Err("Queue overflow: Cannot add more than 200 tasks.");
        }
        self.tasks.push(task);
        self.tasks.sort_unstable_by(|a, b| b.priority.cmp(&a.priority));
        Ok(())
    }

    fn update_task_priority(&mut self, id: usize, new_priority: i32) -> Result<(), &'static str> {
        if let Some(task) = self.tasks.iter_mut().find(|t| t.id == id) {
            task.priority = new_priority;
            self.tasks.sort_unstable_by(|a, b| b.priority.cmp(&a.priority));
            Ok(())
        } else {
            Err("Task not found.")
        }
    }

    fn remove_task(&mut self, id: usize) -> Result<(), &'static str> {
        if let Some(pos) = self.tasks.iter().position(|t| t.id == id) {
            self.tasks.remove(pos);
            Ok(())
        } else {
            Err("Task not found.")
        }
    }
}

fn main() {
    let mut pq = PriorityQueue::new();

    // Example usage:
    let _ = pq.add_task(Task::new(1, 5, String::from("Task 1")));
    let _ = pq.add_task(Task::new(2, 10, String::from("Task 2")));
    let _ = pq.update_task_priority(1, 15);
    let _ = pq.remove_task(2);
}
