use std::collections::BinaryHeap;

pub fn priority_queue<T: PartialEq + Clone> () -> SmallVec<[T; 200]> {
    let mut small_vec = SmallVec::with_capacity(200);
    small_vec.resize(200, T::default());
    small_vec
}

pub fn push<T: PartialEq + Clone>(mut vec: SmallVec<[T; 200]>, value: T) -> Result<SmallVec<[T; 200]>, String> {
    if vec.len() == 200 {
        return Err("Overflow: cannot add more elements".to_string());
    }
    vec.push(value);
    Ok(vec)
}

pub fn update_priority<T: PartialEq + Clone>(mut vec: SmallVec<[T; 200]>, index: usize, new_priority: T) -> Result<SmallVec<[T; 200]>, String> {
    if index >= vec.len() {
        return Err("Index out of bounds".to_string());
    }
    vec[index] = new_priority;
    Ok(vec)
}

pub fn pop<T: PartialEq + Clone>(mut vec: SmallVec<[T; 200]>) -> Result<T, String> {
    if vec.is_empty() {
        return Err("Queue is empty".to_string());
    }
    Ok(vec.pop().unwrap())
}
