const MaxEntries = 20000

func main() {
	files := []string{"log1.txt", "log2.txt", "log3.txt"} // Add your log file paths here
	logCounts := make(map[string]int)
	var mu sync.Mutex

	wg := sync.WaitGroup{}
	fileCh := make(chan string, len(files))

	for _, file := range files {
		fileCh <- file
	}
	close(fileCh)

	for i := 0; i < len(files); i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			for file := range fileCh {
				processFile(file, logCounts, &mu)
			}
		}()
	}
	wg.Wait()
}

func processFile(file string, logCounts map[string]int, mu *sync.Mutex) {
	f, err := os.Open(file)
	if err != nil {
		return
	}
	defer f.Close()

	scanner := bufio.NewScanner(f)
	for scanner.Scan() {
		logEntry := scanner.Text()
		mu.Lock()
		if len(logCounts) < MaxEntries {
			logCounts[logEntry]++
		}
		mu.Unlock()
	}
}
