type LogProcessor struct {
	mu      sync.RWMutex
	counts  map[string]int
	quit    chan bool
}

func NewLogProcessor() *LogProcessor {
	return &LogProcessor{
		counts: make(map[string]int),
		quit:   make(chan bool),
	}
}

func (p *LogProcessor) ProcessFile(filePath string) {
	file, err := os.Open(filePath)
	if err != nil {
		fmt.Printf("Error opening file: %v\n", err)
		return
	}
	defer file.Close()

	reader := bufio.NewReader(file)
	for {
		line, err := reader.ReadString('\n')
		if err != nil {
			fmt.Printf("Error reading line: %v\n", err)
			break
		}
		line = strings.TrimSpace(line)
		if line == "" {
			continue
		}

		p.mu.RLock()
		key := line
		if _, exists := p.counts[key]; exists {
			p.counts[key]++
		} else {
			p.counts[key] = 1
		}
		p.mu.RUnlock()
	}
}

func (p *LogProcessor) Shutdown() {
	p.quit <- true
}

func (p *LogProcessor) GetCount(key string) int {
	p.mu.RLock()
	defer p.mu.RUnlock()
	return p.counts[key]
}

func (p *LogProcessor) Increment(key string) {
	p.mu.Lock()
	defer p.mu.Unlock()
	p.counts[key]++
}

func (p *LogProcessor) Delete(key string) {
	p.mu.Lock()
	defer p.mu.Unlock()
	delete(p.counts, key)
}

