import queue

def shortest_path_distance(graph, num_nodes):
    # Initialize distance matrix
    dist = [[float('inf')] * num_nodes for _ in range(num_nodes)]
    for i in range(num_nodes):
        dist[i][i] = 0

    # Initialize queue
    q = queue.Queue()

    # Add initial pairs
    for i in range(num_nodes):
        for j in range(num_nodes):
            if i != j:
                q.put((i, j))

    while not q.empty():
        u, v = q.get()
        if dist[u][v] > graph[u][v]:
            dist[u][v] = graph[u][v]
            q.put((u, v))

    return dist

