    fn new() -> Self {
        EmployeeDatabase {
            data: ArrayVec::new(),
            logs: Vec::new(),
        }
    }

    fn insert(&mut self, employee: Employee) {
        if self.data.len() >= 100 {
            panic!("Cannot insert more than 100 employees");
        }
        self.data.push(employee);
        self.logs.push(format!("Inserted employee with ID: {}", employee.id));
    }

    fn get(&self, employee_id: u32) -> Option<&Employee> {
        for emp in &self.data {
            if emp.id == employee_id {
                return Some(emp);
            }
        }
        None
    }

    fn remove(&mut self, employee_id: u32) {
        for i in (0..self.data.len()).rev() {
            if self.data[i].id == employee_id {
                self.data.remove(i);
                self.logs.push(format!("Removed employee with ID: {}", employee_id));
                break;
            }
        }
    }

    fn average_scores(&self) -> HashMap<u32, f64> {
        let mut avg_scores = HashMap::new();
        for emp in &self.data {
            let sum = emp.scores.iter().sum();
            let count = emp.scores.len() as f64;
            let avg = sum / count;
            *avg_scores.entry(emp.id).or_insert(0.0) += avg;
        }
        avg_scores
    }

    fn log(&self) -> Vec<String> {
        self.logs.clone()
    }
