    fn remove(&mut self, employee_id: u32) {
        for i in (0..self.data.len()).rev() {
            if self.data[i].id == employee_id {
                self.data.remove(i);
                self.logs.push(format!("Removed employee: {}", employee_id));
                break;
            }
        }
    }

    fn list_all(&self) -> Vec<Employee> {
        self.data.deref().clone()
    }

    fn log(&self, message: &str) {
        self.logs.push(message.to_string());
    }
}

