int longestConsecutiveSequence(const std::vector<int>& nums) {
    std::unordered_map<int, bool> seen;
    int maxLen = 0;

    for (int num : nums) {
        if (!seen[num]) {
            int currentLen = 1;
            // Check for consecutive numbers in the forward direction
            while (seen.find(num + 1) != seen.end()) {
                currentLen++;
                num += 1;
            }
            // Check for consecutive numbers in the backward direction
            while (seen.find(num - 1) != seen.end()) {
                currentLen++;
                num -= 1;
            }
            seen[num] = true;
            maxLen = std::max(maxLen, currentLen);
        }
    }

    return maxLen;
}

