using namespace std;

int longestConsecutiveSequence(vector<int> arr) {
    if (arr.empty()) return 0;

    unordered_map<int, bool> seen;
    int maxLen = 1;

    for (int num : arr) {
        if (!seen[num]) {
            seen[num] = true;
            int currentLen = 1;
            // Check left and right
            int left = num - 1;
            while (seen.find(left) != seen.end()) {
                currentLen++;
                left--;
            }
            int right = num + 1;
            while (seen.find(right) != seen.end()) {
                currentLen++;
                right++;
            }
            seen[num] = false; // Remove from map to avoid reprocessing
            maxLen = max(maxLen, currentLen);
        }
    }

    return maxLen;
}

