        raise ValueError("Dictionary cannot exceed 1000 entries.")

    def insert(key, value):
        """Insert a new entry into the dictionary."""
        if key in data_dict:
            raise ValueError("Key already exists.")
        data_dict[key] = value

    def update(key, value):
        """Update an existing entry in the dictionary."""
        if key not in data_dict:
            raise ValueError("Key does not exist.")
        data_dict[key] = value

    def delete(key):
        """Delete an entry from the dictionary."""
        if key not in data_dict:
            raise ValueError("Key does not exist.")
        del data_dict[key]

    def fetch(key):
        """Fetch an entry by its unique identifier."""
        if key not in data_dict:
            raise ValueError("Key does not exist.")
        return data_dict[key]

    return insert, update, delete, fetch

