use std::collections::VecDeque;

fn cumulative_sum(vec_deque: &mut VecDeque<u32>) -> u32 {
    if vec_deque.is_empty() {
        return 0;
    }

    let mut result = 0;
    let mut temp = VecDeque::new();

    while !vec_deque.is_empty() {
        let val = vec_deque.pop_front().unwrap();
        temp.push_back(val);
        result += val;
    }

    // Ensure the total elements do not exceed 200
    if temp.len() > 200 {
        return 0;
    }

    // Ensure the VecDeque does not contain more than 10 elements
    if temp.len() > 10 {
        return 0;
    }

    // Reinsert elements back into the original VecDeque in original order
    for val in temp {
        vec_deque.push_back(val);
    }

    result
}
