    fn compute_median(map: &BTreeMap<i32, i32>) -> i32 {
        let len = map.len();
        if len % 2 == 1 {
            // Odd number of elements
            let mid = len / 2;
            map.keys().nth(mid).unwrap().clone()
        } else {
            // Even number of elements
            let mid1 = (len / 2) - 1;
            let mid2 = len / 2;
            let left = map.keys().nth(mid1).unwrap().clone();
            let right = map.keys().nth(mid2).unwrap().clone();
            if left < right {
                left
            } else {
                right
            }
        }
    }

    // Example usage
    let mut current_median = 0;
    for i in 0..5000 {
        let value = i as i32;
        let updated_map = add_element(stream, value);
        current_median = compute_median(&updated_map);
        println!("Current median: {}", current_median);
        stream = updated_map;
