	for price := range stockPrices {
		buffer = append(buffer, price)
		if len(buffer) == 1000 {
			avg := computeAverage(buffer)
			averages <- avg
			buffer = buffer[:0] // Reset buffer after processing
		}
	}
	if len(buffer) > 0 {
		averages <- computeAverage(buffer)
	}
}

// computeAverage calculates the average of a slice of float64
func computeAverage(prices []float64) float64 {
	sum := 0.0
	for _, price := range prices {
		sum += price
	}
	return sum / float64(len(prices))
}

func main() {
	stockPrices := make(chan float64, 1000)
	averages := make(chan float64)

	var wg sync.WaitGroup
	wg.Add(1)

	go func() {
		defer wg.Done()
		processStockPrices(stockPrices, averages)
