type Book struct {
	Title          string
	Author         string
	Year           int
	CurrentlyIssued bool
}

type Library struct {
	Books map[string]*Book
}

func NewLibrary() *Library {
	return &Library{Books: make(map[string]*Book)}
}

func (l *Library) AddBook(title, author string, year int) {
	if _, exists := l.Books[title]; exists {
		fmt.Println("Book already exists.")
		return
	}
	l.Books[title] = &Book{Title: title, Author: author, Year: year, CurrentlyIssued: false}
	fmt.Println("Book added:", title)
}

func (l *Library) RemoveBook(title string) {
	if _, exists := l.Books[title]; !exists {
		fmt.Println("Book not found.")
		return
	}
	delete(l.Books, title)
	fmt.Println("Book removed:", title)
}

func (l *Library) UpdateBookStatus(title string, issued bool) {
	if book, exists := l.Books[title]; exists {
		book.CurrentlyIssued = issued
		status := "available"
		if issued {
			status = "issued"
		}
		fmt.Printf("Book \"%s\" status updated to %s.\n", title, status)
	} else {
		fmt.Println("Book not found.")
	}
}

func (l *Library) SearchBook(title string) {
	if book, exists := l.Books[title]; exists {
		fmt.Printf("Found Book: Title=\"%s\", Author=\"%s\", Year=%d, Issued=%v\n",
			book.Title, book.Author, book.Year, book.CurrentlyIssued)
	} else {
		fmt.Println("Book not found.")
	}
}

