import threading
import time
from queue import Queue

class LogProcessor:
    def __init__(self, max_size=1500, capacity_threshold=0.9):
        self.queue = Queue(maxsize=max_size)
        self.capacity_threshold = capacity_threshold
        self.max_size = max_size
        self.is_processing = False

    def start(self):
        self.is_processing = True
        self._process_logs()

    def _process_logs(self):
        while self.is_processing:
            if self.queue.qsize() < self.max_size:
                self._enqueue_log("Sample log entry")
            else:
                # Check if queue is at or above capacity threshold
                if self.queue.qsize() >= self.max_size * self.capacity_threshold:
                    self._dequeue_logs()
            time.sleep(0.1)

    def _enqueue_log(self, log_message):
        if self.queue.full():
            self._dequeue_logs()
        self.queue.put(log_message)

    def _dequeue_logs(self):
        for _ in range(self.queue.qsize()):
            self.queue.get()

    def stop(self):
        self.is_processing = False
        while not self.queue.empty():
            self._dequeue_logs()
        print("Log processor stopped")

def main():
    processor = LogProcessor(max_size=1500, capacity_threshold=0.9)
    thread = threading.Thread(target=processor.start)
    thread.start()

    # Simulate log messages
    for i in range(1000):
        processor._enqueue_log(f"Log message {i}")

    # Wait for the thread to finish
    thread.join()
    processor.stop()

if __name__ == "__main__":
    main()
