        if len(self.data) >= 365:
            raise ValueError("Cannot add more than 365 daily aggregates")
        self.data.append((day, min_val, max_val, mean_val))

    def get(self, day):
        for i, (d, _, _, _) in enumerate(self.data):
            if d == day:
                return i
        raise ValueError(f"Day {day} not found")

    def __getitem__(self, day):
        index = self.get(day)
        return self.data[index]
