using namespace std;

void permute(vector<int>& nums, vector<vector<int>>& result, int start, int end) {
    if (start == end) {
        result.push_back(nums);
        return;
    }
    for (int i = start; i < end; i++) {
        swap(nums[i], nums[i + 1]);
        permute(nums, result, start + 1, end);
        swap(nums[i], nums[i + 1]);
    }
}

int main() {
    vector<int> nums = {1, 2, 3};
    vector<vector<int>> result;
    permute(nums, result, 0, nums.size());
    for (const auto& perm : result) {
        for (int num : perm) {
            cout << num << " ";
        }
        cout << endl;
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <set>

using namespace std;

void generatePermutations(vector<int>& nums, vector<vector<int>>& permutations, vector<int>& temp, int index) {
    if (index == nums.size()) {
        permutations.push_back(temp);
        return;
    }

    for (int i = 0; i < nums.size(); ++i) {
        if (i > 0 && nums[i] == nums[i-1]) continue;

        // Avoid duplicates by checking if the current element is already in the temp
        if (index > 0 && temp[index-1] == nums[i]) continue;

        temp.push_back(nums[i]);
        generatePermutations(nums, permutations, temp, index + 1);
        temp.pop_back();
    }
}

int main() {
    vector<int> nums = {1, 2, 3, 4, 5};
    vector<vector<int>> permutations;
    vector<int> temp;

    generatePermutations(nums, permutations, temp, 0);

    // Display results
    cout << "Unique permutations:" << endl;
    for (const auto& perm : permutations) {
        for (int num : perm) {
            cout << num << " ";
        }
        cout << endl;
    }

    return 0;
}

#include <iostream>
