#include <stack>
#include <algorithm>

using namespace std;

void permute(vector<int>& nums, vector<vector<int>>& result, vector<int>& temp, stack<int>& stack) {
    if (temp.size() == nums.size()) {
        result.push_back(temp);
        return;
    }

    for (int i = 0; i < nums.size(); ++i) {
        if (temp.size() > 0 && temp[temp.size() - 1] == nums[i]) continue;
        if (stack.size() > 0 && stack.top() == nums[i]) continue;

        temp.push_back(nums[i]);
        stack.push(nums[i]);

        permute(nums, result, temp, stack);

        temp.pop_back();
        stack.pop();
    }
}

int main() {
    vector<int> nums = {1, 2, 3};
    vector<vector<int>> result;
    vector<int> temp;
    stack<int> stack;

    permute(nums, result, temp, stack);

    for (const auto& perm : result) {
        for (int num : perm) {
            cout << num << " ";
        }
        cout << endl;
    }

    return 0;
}

