void countUniqueWords(const std::string& input) {
    std::unordered_set<std::string> uniqueWords;
    std::unordered_map<std::string, int> wordOccurrences;
    std::string preprocessedString;
    std::string word;

    // Preprocessing: Normalize case and remove punctuation
    for (char ch : input) {
        if (std::isalpha(ch) || std::isspace(ch)) {
            preprocessedString += std::tolower(ch);
        }
    }

    std::istringstream stream(preprocessedString);
    while (stream >> word) {
        uniqueWords.insert(word);
        wordOccurrences[word]++;
    }

    // Output results
    std::cout << "Unique word count: " << uniqueWords.size() << std::endl;
    for (const auto& entry : wordOccurrences) {
        std::cout << entry.first << ": " << entry.second << std::endl;
    }
}

int main() {
    std::string input = "Hello, world! Hello, C++ world. Programming is fun.";
    countUniqueWords(input);
    return 0;
}
