int countUniqueWords(const std::string& input) {
    std::unordered_set<std::string> uniqueWords;
    std::map<std::string, int> wordCount;

    // Normalize case
    std::string normalizedInput = input;
    for (char& c : normalizedInput) {
        if (std::isalpha(c)) {
            c = std::tolower(c);
        }
    }

    // Remove punctuation
    std::string processedInput;
    for (char c : normalizedInput) {
        if (std::ispunct(c)) {
            continue;
        }
        processedInput += c;
    }

    // Split into words
    std::istringstream iss(processedInput);
    std::string word;
    while (iss >> word) {
        uniqueWords.insert(word);
        wordCount[word]++;
    }

    // Output count and breakdown
    std::cout << "Number of unique words: " << uniqueWords.size() << std::endl;
    for (const auto& pair : wordCount) {
        std::cout << "Word: " << pair.first << ", Count: " << pair.second << std::endl;
    }

    return uniqueWords.size();
}

#include <iostream>
#include <string>
#include <unordered_set>
#include <cctype>
#include <sstream>
#include <map>

using namespace std;

int countUniqueWords(const string& input) {
    unordered_set<string> uniqueWords;
    map<string, int> wordCount;

    // Normalize case and remove punctuation
    string normalizedInput = input;
    for (char& c : normalizedInput) {
        if (isalpha(c)) {
            c = tolower(c);
        } else if (ispunct(c)) {
            c = ' ';
        }
    }

    istringstream iss(normalizedInput);
    string word;
    int count = 0;

    while (iss >> word) {
        uniqueWords.insert(word);
        wordCount[word]++;
        count++;
        if (count >= 100) {
            break;
        }
    }

    cout << "Unique words count: " << count << endl;
    cout << "Word counts:" << endl;
    for (const auto& pair : wordCount) {
        cout << pair.first << ": " << pair.second << endl;
    }

    return count;
}

#include <iostream>
#include <vector>
#include <string>
#include <cctype>
#include <algorithm>
#include <unordered_map>

using namespace std;

void processString(const string& input, vector<string>& words) {
    // Normalize case
    for (auto& c : input) {
        if (isalpha(c)) {
            c = tolower(c);
        }
    }

    // Remove punctuation
    string processed;
    for (char c : input) {
        if (isalnum(c)) {
            processed += c;
        }
    }

    // Split into words
    istringstream iss(processed);
    string word;
    while (iss >> word) {
        words.push_back(word);
    }
}

int main() {
    string input = "Hello, world! This is a test. Hello again.";
    vector<string> words;

    processString(input, words);

    // Check size
    if (words.size() > 100) {
        cout << "Error: Vector exceeds maximum size of 100." << endl;
        return 1;
    }

    // Count unique words
    unordered_map<string, int> wordCount;
    for (const auto& w : words) {
        wordCount[w]++;
    }

    // Output total count and breakdown
    cout << "Total unique words: " << wordCount.size() << endl;
    for (const auto& pair : wordCount) {
        cout << pair.first << ": " << pair.second << endl;
    }

    return 0;
}

