import java.util.PriorityQueue;
import java.util.Comparator;

class EmergencyAlert {
    int severity;
    String timestamp;

    public EmergencyAlert(int severity, String timestamp) {
        this.severity = severity;
        this.timestamp = timestamp;
    }

    @Override
    public String toString() {
        return "Severity: " + severity + ", Timestamp: " + timestamp;
    }
}

public class EmergencyAlertSystem {

    private PriorityQueue<EmergencyAlert> alertQueue;

    public EmergencyAlertSystem() {
        alertQueue = new PriorityQueue<>(Comparator.comparingInt((EmergencyAlert alert) -> -alert.severity));
    }

    public void addAlert(int severity, String timestamp) {
        alertQueue.offer(new EmergencyAlert(severity, timestamp));
    }

    public void processEmergencyAlerts() {
        while (!alertQueue.isEmpty()) {
            EmergencyAlert alert = alertQueue.poll();
            displayAlert(alert);
        }
    }

    private void displayAlert(EmergencyAlert alert) {
        System.out.println("Processing Alert: " + alert);
    }

    public static void main(String[] args) {
        EmergencyAlertSystem system = new EmergencyAlertSystem();
        system.addAlert(5, "2023-01-01T08:00:00");
        system.addAlert(3, "2023-01-01T09:00:00");
        system.addAlert(7, "2023-01-01T07:00:00");

        system.processEmergencyAlerts();
    }
}
