import java.util.PriorityQueue;

public class EmergencyAlertSystem {
    private PriorityQueue<Alert> alertQueue;

    public EmergencyAlertSystem() {
        alertQueue = new PriorityQueue<>();
    }

    public void addAlert(String severity, long timestamp) {
        alertQueue.add(new Alert(severity, timestamp));
    }

    public void processEmergencyAlerts() {
        while (!alertQueue.isEmpty()) {
            Alert currentAlert = alertQueue.peek();
            System.out.println("Processing alert: " + currentAlert.getSeverity() + " at " + currentAlert.getTimestamp());
            alertQueue.remove();
        }
    }

    // Inner class to represent an alert with severity and timestamp
    private static class Alert implements Comparable<Alert> {
        private String severity;
        private long timestamp;

        public Alert(String severity, long timestamp) {
            this.severity = severity;
            this.timestamp = timestamp;
        }

        public String getSeverity() {
            return severity;
        }

        public long getTimestamp() {
            return timestamp;
        }

        @Override
        public int compareTo(Alert other) {
            // Prioritize by severity (critical first)
            return Integer.compare(Integer.parseInt(this.severity), Integer.parseInt(other.severity));
        }
    }
}
