    // Add a score to the top of the stack
    void push(int score) {
        if (scores.size() >= MAX_SIZE) {
            throw runtime_error("Cannot add more than 10 scores");
        }
        scores.push_back(score);
    }

    // Retrieve a list of exactly 10 high scores
    vector<int> loadHighScores() {
        return scores;
    }

    // Sort scores in descending order
    void sortDescending() {
        sort(scores.begin(), scores.end(), greater<int>());
    }

    // Search for a specific score
    bool contains(int score) {
        return find(scores.begin(), scores.end(), score) != scores.end();
    }
