use std::collections::BTreeMap;

fn track_inventory_changes() -> BTreeMap<u32, i32> {
    let mut inventory_changes = BTreeMap::new();

    fn add_inventory_log(inventory_changes: &mut BTreeMap<u32, i32>, product_id: u32, change: i32) {
        inventory_changes.entry(product_id).and_modify(|e| *e += change).or_insert(change);
    }

    fn report_changes(inventory_changes: &BTreeMap<u32, i32>) {
        for (product_id, change) in inventory_changes.iter() {
            println!("Product ID: {}, Inventory Change: {}", product_id, change);
        }
    }

    add_inventory_log(&mut inventory_changes, 101, 5);
    add_inventory_log(&mut inventory_changes, 202, -3);
    add_inventory_log(&mut inventory_changes, 101, 2);

    report_changes(&inventory_changes);

    inventory_changes
}
