void detectDuplicateErrors(vector<int> errors) {
    unordered_set<int> uniqueDuplicates;
    map<int, int> errorCount;

    for (int error : errors) {
        if (errorCount.find(error) != errorCount.end()) {
            uniqueDuplicates.insert(error);
            errorCount[error]++;
        } else {
            errorCount[error] = 1;
        }
    }

    cout << "Unique duplicate error codes: " << uniqueDuplicates.size() << endl;
    cout << "Count of unique duplicate error codes: " << uniqueDuplicates.size() << endl;
}

