        return []

    intervals.sort()
    merged = [intervals[0]]

    for current in intervals[1:]:
        last = merged[-1]
        if current[0] < last[1]:
            # Overlapping, merge them
            merged[-1] = (last[0], current[1])
        else:
            # No overlap, add as new interval
            merged.append(current)

    return merged
