from collections import deque

def manageEmergencyQueue():
    queue = deque()
    max_size = 10

    def add_patient(patient_id, severity):
        if len(queue) < max_size:
            queue.append((patient_id, severity))
        else:
            # If the queue is full, remove the least severe patient
            # (by default, the first element is the least severe)
            queue.popleft()
            queue.append((patient_id, severity))

    def get_next_patient():
        if queue:
            return queue.popleft()
        return None

    def reevaluate_priority(patient_id, new_severity):
        # Find the patient in the queue
        for i in range(len(queue)):
            if queue[i][0] == patient_id:
                queue[i] = (patient_id, new_severity)
                break

    return {
        'add_patient': add_patient,
        'get_next_patient': get_next_patient,
        'reevaluate_priority': reevaluate_priority
    }
