use std::vec::Vec;

fn combine_small_data_streams(streams: Vec<Vec<i32>>) -> Vec<i32> {
    let mut small_vec = Vec::new();
    let max_items = 10;

    for stream in streams {
        for item in stream {
            if small_vec.len() < max_items {
                small_vec.push(item);
            } else {
                // If the SmallVec is full, we need to allocate more memory
                let new_capacity = small_vec.len() * 2;
                let mut new_vec = Vec::with_capacity(new_capacity);
                new_vec.extend(small_vec);
                new_vec.push(item);
                small_vec = new_vec;
            }
        }
    }

    small_vec
}
