	buffer bytes.Buffer
	mutex  sync.Mutex
}

func (ep *EventProcessor) logEvents(event string) {
	ep.mutex.Lock()
	defer ep.mutex.Unlock()

	ep.buffer.WriteString(event + "\n")

	if ep.buffer.Len() >= maxBufferSize {
		ep.flushBuffer()
	}
}

func (ep *EventProcessor) flushBuffer() {
	if ep.buffer.Len() == 0 {
		return
	}

	// Simulate processing the batched data
	fmt.Println("Flushing buffer:")
	fmt.Print(ep.buffer.String())

	// Clear the buffer
	ep.buffer.Reset()
}

func (ep *EventProcessor) startPeriodicFlush() {
	ticker := time.NewTicker(flushInterval * time.Second)
	defer ticker.Stop()

	for range ticker.C {
		ep.mutex.Lock()
		ep.flushBuffer()
		ep.mutex.Unlock()
	}
}

func main() {
