type event struct {
	ID   string
	Data interface{}
}

type buffer struct {
	capacity int
	data     []event
	mutex    sync.Mutex
}

func (b *buffer) write(event event) error {
	b.mutex.Lock()
	defer b.mutex.Unlock()

	if len(b.data) >= b.capacity {
		return errors.New("buffer full")
	}

	b.data = append(b.data, event)
	return nil
}

func (b *buffer) read() ([]event, error) {
	b.mutex.Lock()
	defer b.mutex.Unlock()

	if len(b.data) == 0 {
		return nil, errors.New("buffer empty")
	}

	result := make([]event, len(b.data))
	copy(result, b.data)
	b.data = b.data[:0]
	return result, nil
}

func logEvents(events []event, capacity int) (*buffer, error) {
	if capacity <= 0 {
		return nil, errors.New("capacity must be greater than 0")
	}

	buffer := &buffer{
		capacity: capacity,
		data:     make([]event, 0, capacity),
	}

	go func() {
		for _, event := range events {
			if err := buffer.write(event); err != nil {
				fmt.Println("Error writing event:", err)
			}
		}
	}()

	// Simulate periodic flushing
	go func() {
