using namespace std;

class Meeting {
public:
    int start;
    int end;
    Meeting(int s, int e) : start(s), end(e) {}
};

vector<Meeting> mergeMeetingTimes(vector<pair<int, int>> intervals) {
    if (intervals.empty()) return {};

    // Sort intervals by start time
    sort(intervals.begin(), intervals.end(), [](const pair<int, int>& a, const pair<int, int>& b) {
        return a.first < b.first;
    });

    priority_queue<Meeting, vector<Meeting>, decltype(&Meeting::start)> pq;
    pq.push(intervals[0]);

    for (size_t i = 1; i < intervals.size(); ++i) {
        auto current = intervals[i];
        auto top = pq.top();

        if (current.start <= top.end) {
            // Overlapping, merge
            pq.pop();
            pq.push(Meeting(top.start, max(top.end, current.end)));
        } else {
            // No overlap, add as new interval
            pq.push(current);
        }
    }

    vector<Meeting> merged;
    while (!pq.empty()) {
        merged.push_back(pq.top());
        pq.pop();
    }

    return merged;
}

