void mergeMeetingTimes(vector<pair<int, int>>& intervals) {
    if (intervals.empty()) return;

    priority_queue<pair<int, int>, vector<pair<int, int>>, decltype(&compare)> pq;

    // Push the first interval into the priority queue
    pq.push(intervals[0]);

    for (size_t i = 1; i < intervals.size(); ++i) {
        // Compare current interval with the top of the priority queue
        if (intervals[i].first <= pq.top().second) {
            // Overlapping, merge them
            pair<int, int> merged = {pq.top().first, max(pq.top().second, intervals[i].second)};
            pq.pop();
            pq.push(merged);
        } else {
            // No overlap, push as is
            pq.push(intervals[i]);
        }
    }
}

