std::set<std::string> filterUniqueEmails(const std::vector<std::string>& emails) {
    std::set<std::string> uniqueEmails;

    for (const auto& email : emails) {
        // Preprocess the email
        std::string processedEmail;
        std::string normalizedEmail;

        // Convert to lowercase
        std::transform(email.begin(), email.end(), std::back_inserter(processedEmail),
                      [](unsigned char c) { return std::tolower(c); });

        // Normalize dots before "@"
        size_t atIndex = processedEmail.find('@');
        if (atIndex != std::string::npos) {
            std::string beforeAt = processedEmail.substr(0, atIndex);
            std::string afterAt = processedEmail.substr(atIndex + 1);

            // Replace dots with a single dot
            std::string normalizedBeforeAt;
            for (char c : beforeAt) {
                if (c == '.') {
                    normalizedBeforeAt += '.';
                } else {
                    normalizedBeforeAt += c;
                }
            }

            normalizedEmail = normalizedBeforeAt + "@" + afterAt;
        } else {
            normalizedEmail = processedEmail;
        }

        // Add to set
        uniqueEmails.insert(normalizedEmail);
    }

    // Convert set to sorted list
    std::vector<std::string> sortedEmails(uniqueEmails.begin(), uniqueEmails.end());
    std::sort(sortedEmails.begin(), sortedEmails.end());

    return sortedEmails;
}

