void batchProcessTasks(std::list<int> tasks) {
    // Limit the list to 50 tasks
    if (tasks.size() > 50) {
        tasks.erase(tasks.begin(), tasks.end() - 50);
    }

    // Mark completed tasks (example: status is 2)
    std::list<int> completed;
    for (auto it = tasks.begin(); it != tasks.end(); ++it) {
        if (*it == 2) {
            completed.push_back(*it);
        }
    }

    // Remove completed tasks from the original list
    for (auto it = completed.begin(); it != completed.end(); ++it) {
        tasks.erase(std::remove(tasks.begin(), tasks.end(), *it));
    }
}

