        "total_matches": 0,
        "total_mismatches": 0,
        "differences": []
    }

    for i in range(4):
        s1 = seq1[i]
        s2 = seq2[i]

        # Check if both strings are in uppercase
        if not (s1.isupper() and s2.isupper()):
            report["total_mismatches"] += 1
            report["differences"].append(i)

        # Check if strings are equal
        if s1 == s2:
            report["total_matches"] += 1

