package main

func rotateArray(arr *[5]int, k int) {
	n := len(arr)
	k = k % n
	if k == 0 {
		return
	}
	reverse := func(a *[5]int, start, end int) {
		for start < end {
			a[start], a[end] = a[end], a[start]
			start++
			end--
		}
	}
	reverse(arr, 0, n-1)
	reverse(arr, 0, k-1)
	reverse(arr, k, n-1)
}

func main() {
	arr := [5]int{1, 2, 3, 4, 5}
	rotateArray(&arr, 3)
}
