import "fmt"

func rotateArray(arr []int, k int) {
    if len(arr) == 0 || k == 0 {
        return
    }
    n := len(arr)
    k %= n
    for i := 0; i < k; i++ {
        last := arr[n-1]
        for j := n - 1; j > 0; j-- {
            arr[j] = arr[j-1]
        }
        arr[0] = last
    }
}
