    fn new() -> Self {
        Self {
            grades: ArrayVec::new(),
        }
    }

    fn add_grade(&mut self, student_id: u32, grade: f32) {
        if self.grades.len() < self.grades.capacity() {
            self.grades.push(StudentGrade { student_id, grade });
        }
    }

    fn update_grade(&mut self, student_id: u32, new_grade: f32) {
        if let Some(student_grade) = self.grades.iter_mut().find(|g| g.student_id == student_id) {
            student_grade.grade = new_grade;
        }
    }

    fn delete_grade(&mut self, student_id: u32) {
        if let Some(pos) = self.grades.iter().position(|g| g.student_id == student_id) {
            self.grades.remove(pos);
        }
    }

    fn compute_average(&self) -> Option<f32> {
        if self.grades.is_empty() {
            None
        } else {
            Some(self.grades.iter().map(|g| g.grade).sum::<f32>() / self.grades.len() as f32)
        }
    }
}

