bool validateBrackets(const std::string& str) {
    std::stack<char> bracketStack;
    for (char ch : str) {
        if (ch == '{' || ch == '(' || ch == '[') {
            bracketStack.push(ch);
        } else if (ch == '}' || ch == ')' || ch == ']') {
            if (bracketStack.empty()) {
                return false;
            }
            char top = bracketStack.top();
            bracketStack.pop();
            if ((ch == '}' && top != '{') || (ch == ')' && top != '(') || (ch == ']' && top != '[')) {
                return false;
            }
        }
    }
    return bracketStack.empty();
}
