    for (char c : brackets) {
        if (c == '{' || c == '[' || c == '(' || c == ')') {
            stack.push_back(c);
            if (stack.size() > 10) {
                return false;
            }
        } else if (c == '}') {
            if (stack.empty() || stack.back() != '{') {
                return false;
            }
            stack.pop_back();
        } else if (c == ']') {
            if (stack.empty() || stack.back() != '[') {
                return false;
            }
            stack.pop_back();
        } else if (c == ')') {
            if (stack.empty() || stack.back() != '(') {
                return false;
            }
            stack.pop_back();
        }
    }
    return stack.empty();
