using namespace std;

class SurveyManager {
public:
    void organizeSurveyData(const vector<pair<int, int>>& responses) {
        if (responses.size() > 100) {
            throw invalid_argument("Cannot store more than 100 participants' responses.");
        }

        // Sort responses by participant ID
        sort(responses.begin(), responses.end(), [](const pair<int, int>& a, const pair<int, int>& b) {
            return a.first < b.first;
        });

        // Store responses in vector
        surveyResponses = responses;
    }

    vector<pair<int, int>> getResponses() const {
        return surveyResponses;
    }

    void updateRating(int participantId, int newRating) {
        auto it = find_if(surveyResponses.begin(), surveyResponses.end(), [&](const pair<int, int>& response) {
            return response.first == participantId;
        });
        if (it != surveyResponses.end()) {
            it->second = newRating;
        } else {
            throw out_of_range("Participant not found");
        }
    }

    void deleteRating(int participantId) {
        auto it = find_if(surveyResponses.begin(), surveyResponses.end(), [&](const pair<int, int>& response) {
            return response.first == participantId;
        });
        if (it != surveyResponses.end()) {
            surveyResponses.erase(it);
        } else {
            throw out_of_range("Participant not found");
        }
    }

private:
    vector<pair<int, int>> surveyResponses;
};

