	if id <= 0 {
		return errors.New("ID must be positive")
	}

	// Check if ID already exists
	if existing, ok := e.ID; ok && existing == id {
		return errors.New("ID already exists")
	}

	// Create new employee
	newEmp := &Employee{
		ID:   id,
		Name: name,
		Position: position,
		Salary: salary,
	}

	// Add to map
	e[id] = newEmp

	// Sort by ID for efficient retrieval
	sort.Slice(e, func(i, j int) bool { return e[i].ID < e[j].ID })

	return nil
}

func (e *Employee) UpdateEmployee(id int, name, position, salary string) error {
	if id <= 0 {
		return errors.New("ID must be positive")
	}

	// Check if ID exists
	if existing, ok := e.ID; ok && existing == id {
		e.Name = name
		e.Position = position
		e.Salary = salary
		return nil
	}

	return errors.New("Employee not found")
}

func (e *Employee) GetEmployee(id int) (*Employee, error) {
	if id <= 0 {
		return nil, errors.New("ID must be positive")
	}

	employee, ok := e[id]
	if !ok {
		return nil, errors.New("Employee not found")
	}

	return employee, nil
}

