	}
	for i := 0; i < len(e); i++ {
		if e[i].ID == id {
			e[i].Name = name
			e[i].Position = position
			e[i].Salary = salary
			return nil
		}
	}
	return errors.New("Employee not found")
}

func (e *Employee) RetrieveEmployee(id int) (*Employee, error) {
	for i := 0; i < len(e); i++ {
		if e[i].ID == id {
			return &e[i], nil
		}
	}
	return nil, errors.New("Employee not found")
}

func (e *Employee) RemoveEmployee(id int) error {
	for i := 0; i < len(e); i++ {
		if e[i].ID == id {
			e = &e[0:i] + &e[i+1:]
			return nil
		}
	}
	return errors.New("Employee not found")
