#include <vector>

std::vector<double> computeRollingAverages(const std::vector<double>& temperatures, int windowSize) {
    std::vector<double> result;
    if (temperatures.empty() || windowSize <= 0) {
        return result;
    }

    int n = temperatures.size();
    if (windowSize > n) {
        return result;
    }

    for (int i = 0; i < n; ++i) {
        int start = std::max(0, i - windowSize + 1);
        int end = std::min(n - 1, i);
        double average = (double)(temperatures[start] + temperatures[end]) / 2;
        result.push_back(average);
    }

    return result;
}

