func (b *LogBuffer) AddEntry(entry LogEntry) {
	b.mutex.Lock()
	defer b.mutex.Unlock()

	if len(b.entries) >= b.threshold {
		b.buffer.Flush()
		b.entries = b.entries[:b.threshold]
	}

	b.buffer.Append(entry)
	b.entries = append(b.entries, entry)
}

