// LogEntry represents a log entry
type LogEntry struct {
	Message string
}

// Buffer is a priority queue for log entries
type Buffer struct {
	logs     []LogEntry
	entries  int
	mu       sync.Mutex
}

// Push adds a new log entry to the buffer
func (b *Buffer) Push(log LogEntry) {
	b.mu.Lock()
	defer b.mu.Unlock()
	b.logs = append(b.logs, log)
	b.entries++
	if b.entries > 1000 {
		b.pop()
	}
}

// Pop removes the oldest log entry
func (b *Buffer) Pop() LogEntry {
	b.mu.Lock()
	defer b.mu.Unlock()
	if len(b.logs) == 0 {
		return LogEntry{}
	}
	result := b.logs[0]
	b.logs = b.logs[1:]
	b.entries--
	return result
}

// Get returns the current logs in the buffer
func (b *Buffer) Get() []LogEntry {
	b.mu.Lock()
	defer b.mu.Unlock()
	return b.logs
}

// SearchError looks for specific error patterns and counts their occurrences
func (b *Buffer) SearchError(pattern string) map[string]int {
	b.mu.Lock()
	defer b.mu.Unlock()
	counts := make(map[string]int)
	for _, log := range b.logs {
		if strings.Contains(log.Message, pattern) {
			counts[log.Message]++
		}
	}
	return counts
}

// ProcessLogFile processes log file entries and manages the buffer
func processLogFile(logs []LogEntry) {
	buffer := &Buffer{
		logs:     logs,
		entries:  0,
	}

	for i := 0; i < len(logs); i++ {
		buffer.Push(logs[i])
	}

	// Print buffer contents
	fmt.Println("Buffer contents:")
	for _, log := range buffer.Get() {
		fmt.Printf("%s\n", log.Message)
	}

	// Search for error patterns
	errorCounts := buffer.SearchError("error")
	fmt.Println("\nError counts:")
	for pattern, count := range errorCounts {
		fmt.Printf("%s: %d\n", pattern, count)
