fn detect_cycle_in_graph(graph: &mut [Vec<&str>], n: usize) -> bool {
    let mut visited = HashSet::new();
    let mut rec_stack = HashSet::new();

    for i in 0..n {
        if !visited.contains(&i) {
            if dfs(i, &graph, &mut visited, &mut rec_stack) {
                return true;
            }
        }
    }

    false
}

fn dfs(node: usize, graph: &[Vec<&str>], visited: &mut HashSet<usize>, rec_stack: &mut HashSet<usize>) -> bool {
    visited.insert(node);
    rec_stack.insert(node);

    for neighbor in &graph[node] {
        if !visited.contains(neighbor) {
            if dfs(*neighbor as usize, graph, visited, rec_stack) {
                return true;
            }
        } else if rec_stack.contains(neighbor) {
            return true;
        }
    }

    rec_stack.remove(&node);
    false
}
