use std::collections::HashSet;

fn detect_cycle_in_graph(graph: &mut Vec<Vec<usize>>, n: usize) -> bool {
    let mut visited = vec![false; n];
    let mut rec_stack = vec![false; n];
    let mut cycle_found = false;

    for start in 0..n {
        if !visited[start] {
            let mut stack = HashSet::new();
            stack.insert(start);
            visited[start] = true;
            rec_stack[start] = true;

            while let Some(node) = stack.pop() {
                if rec_stack[node] {
                    // Cycle detected
                    cycle_found = true;
                    break;
                }
                if visited[node] {
                    continue;
                }
                visited[node] = true;
                stack.insert(node);
                rec_stack[node] = true;
            }

            if cycle_found {
                break;
            }
        }
    }

    cycle_found
}
