public class StudentScoreCategorizer {
    public static void categorizeStudentScores(List<String> studentNames, List<Integer> scores) {
        HashMap<String, List<String>> scoreCategories = new HashMap<>();

        // Define score ranges and their corresponding thresholds
        Map<String, Integer> scoreRangeMap = new HashMap<>();
        scoreRangeMap.put("[90-100]", 90);
        scoreRangeMap.put("[80-90)", 80);
        scoreRangeMap.put("[70-80)", 70);
        scoreRangeMap.put("[60-70)", 60);
        scoreRangeMap.put("[50-60)", 50);
        scoreRangeMap.put("[40-50)", 40);
        scoreRangeMap.put("[30-40)", 30);
        scoreRangeMap.put("[20-30)", 20);
        scoreRangeMap.put("[10-20)", 10);
        scoreRangeMap.put("[0-10)", 0);

        // Process each score and categorize
        for (int i = 0; i < scores.size(); i++) {
            int score = scores.get(i);
            String rangeKey = getRangeKey(score, scoreRangeMap);
            List<String> studentsInRange = scoreCategories.computeIfAbsent(rangeKey, k -> new ArrayList<>());
            studentsInRange.add(studentNames.get(i));
            scoreCategories.put(rangeKey, studentsInRange);
        }

        // Ensure the HashMap size does not exceed 5 elements
        if (scoreCategories.size() > 5) {
            Set<String> keysToRemove = new HashSet<>();
            for (String key : scoreCategories.keySet()) {
                if (scoreCategories.get(key).size() == 0) {
                    keysToRemove.add(key);
                }
            }
            for (String key : keysToRemove) {
                scoreCategories.remove(key);
            }
        }
    }

    private static String getRangeKey(int score, Map<String, Integer> scoreRangeMap) {
        String rangeKey = "";
        int threshold = scoreRangeMap.get("[" + score + "-100)");
        if (threshold != null) {
            rangeKey = "[" + score + "-100)";
        } else {
            rangeKey = "[" + score + "-100)";
        }
        return rangeKey;
    }
}
