import java.util.HashMap;

public class StudentScoreCategorizer {
    private static final HashMap<String, List<String>> scoreMap = new HashMap<>();

    public static void categorizeStudentScores(List<String> studentScores) {
        // Initialize the map if it's not already initialized
        if (scoreMap.size() < 5) {
            scoreMap.clear();
        }

        for (String score : studentScores) {
            String[] parts = score.split("-");
            int min = Integer.parseInt(parts[0]);
            int max = Integer.parseInt(parts[1]);

            String key = "[" + min + "-" + max + "]";
            List<String> students = new ArrayList<>();

            // Check if the score is within the range
            if (min <= 100 && max >= 0) {
                if (min <= max) {
                    // Add to the corresponding key
                    if (scoreMap.containsKey(key)) {
                        scoreMap.get(key).add(score);
                    } else {
                        scoreMap.put(key, new ArrayList<>(List.of(score)));
                    }
                }
            }
        }
    }

    public static List<String> getPerformanceTier(String tier) {
        return scoreMap.get(tier);
    }

    public static void main(String[] args) {
        List<String> scores = Arrays.asList("95-100", "85-90", "75-80", "65-70", "55-60");
        categorizeStudentScores(scores);

        System.out.println(getPerformanceTier("[90-100]")); // Should print ["95-100"]
        System.out.println(getPerformanceTier("[80-90)"]); // Should print ["85-90"]
        System.out.println(getPerformanceTier("[70-80)"]); // Should print ["75-80"]
        System.out.println(getPerformanceTier("[60-70)"]); // Should print ["65-70"]
        System.out.println(getPerformanceTier("[50-60)"]); // Should print ["55-60"]
    }
}
