import java.util.*;

public class MeetingScheduler {
    public static ArrayList<String> organizeMeetings(List<Meeting> meetings) {
        PriorityQueue<Meeting> priorityQueue = new PriorityQueue<>();
        ArrayList<String> processedMeetings = new ArrayList<>();

        for (Meeting meeting : meetings) {
            priorityQueue.add(meeting);
        }

        while (!priorityQueue.isEmpty()) {
            Meeting currentMeeting = priorityQueue.poll();
            processedMeetings.add(currentMeeting.getUrgency() + " - " + currentMeeting.getDescription());
        }

        return processedMeetings;
    }
}

