std::pair<std::vector<std::string>, int> deduplicateEmailAddresses(const std::vector<std::string>& emailAddresses) {
    std::unordered_set<std::string> uniqueEmails;
    std::vector<std::string> finalList;
    int duplicatesRemoved = 0;

    for (const auto& email : emailAddresses) {
        if (uniqueEmails.insert(email).second) {
            finalList.push_back(email);
        } else {
            ++duplicatesRemoved;
        }
    }

    return {finalList, duplicatesRemoved};
}

int main() {
    std::vector<std::string> emails = {"example1@gmail.com", "example2@gmail.com", "example1@gmail.com", "example3@gmail.com"};
    auto result = deduplicateEmailAddresses(emails);

    std::cout << "Unique email addresses:\n";
    for (const auto& email : result.first) {
        std::cout << email << "\n";
    }

    std::cout << "Duplicates removed: " << result.second << "\n";

    return 0;
}
